        ["algo" => 35, "uuid" => "930dc7", "name" => "md2", "type" => "hash", "status" => "broken", "title" => "MD2", "description_md" => "MD2 is a cryptographic hash function designed in 1989. It produces a 128-bit (16-byte) hash output. Once widely used for message authentication and checksums, MD2 is now completely broken for cryptographic purposes. Collision attacks are trivial, and it should never be used for security. The algorithm is slow compared to modern alternatives. Still found in legacy systems and old digital signatures, particularly in X.509 certificates. Useful only for historical study or compatibility with ancient systems that cannot be updated.", "mental_model" => "Broken fingerprint reader from the 1980s.", "purpose" => ["compute hash", "legacy compatibility"], "good_for" => ["historical study", "legacy system compatibility"], "avoid_for" => ["security", "modern applications", "new code"], "pros" => ["simple algorithm", "16-byte output"], "cons" => ["broken", "slow", "collision vulnerable", "preimage attacks possible"], "difficulty" => 1, "security" => 1, "quantum_impact" => "Already broken; quantum attacks irrelevant.", "post_quantum_status" => 1, "example" => ["scenario" => "Legacy certificate validation (do not use for new systems)", "input" => ["message" => "example@legacy.com"], "output" => ["hash" => "f4a4ae2ab00e38fc36af5e00e19c0ead"]], "flow" => ["padding", "16 rounds", "compress", "digest"], "related" => ["md4", "md5", "sha1"]],
        ["algo" => 36, "uuid" => "45efe3", "name" => "md4", "type" => "hash", "status" => "broken", "title" => "MD4", "description_md" => "MD4 is a 128-bit cryptographic hash from 1990, designed as a faster alternative to MD2. It outputs 16 bytes of hash. MD4 was broken in 1992 and is severely compromised. Collisions can be generated in seconds. It appears in legacy NTLMv1 authentication in Windows systems and some older protocols. Do not use for any security purpose. Still encountered in penetration testing against legacy Windows domains. Some legacy protocols like LANMAN authentication rely on MD4, making it important to understand when assessing old systems. Modern code should avoid it entirely.", "mental_model" => "Expired security badge with known forgeries.", "purpose" => ["compute hash", "legacy ntlmv1"], "good_for" => ["cracking ntlmv1 hashes", "legacy system assessment"], "avoid_for" => ["security", "new applications", "production systems"], "pros" => ["fast for 1990s era", "simple algorithm"], "cons" => ["completely broken", "collision attacks", "preimage attacks", "ntlmv1 compatibility liability"], "difficulty" => 1, "security" => 1, "quantum_impact" => "Already broken; quantum irrelevant.", "post_quantum_status" => 1, "example" => ["scenario" => "Legacy Windows NTLM assessment", "input" => ["message" => "Password123"], "output" => ["hash" => "8846f7eaee8fb117ad06bdd830b7586c"]], "flow" => ["padding", "64 rounds", "compress", "digest"], "related" => ["md2", "md5", "ntlmv1"]],
        ["algo" => 37, "uuid" => "defc81", "name" => "md5", "type" => "hash", "status" => "broken", "title" => "MD5", "description_md" => "MD5 produces a 128-bit (16-byte) hash. Designed by Ron Rivest in 1992, it became ubiquitous for checksums and fingerprinting. MD5 collisions were demonstrated in 2004 and exploit techniques are now trivial. Collision attacks take seconds on modern hardware. Despite being cryptographically broken, MD5 remains in use for non-security applications like checksums, integrity checks, and deduplication. Found in millions of legacy systems, old certificates, and software repositories. Do not use for security like password hashing or message authentication. Use only for non-critical checksums where collision resistance is not needed.", "mental_model" => "Dented padlock that looks secure but isn't.", "purpose" => ["compute hash", "checksums", "fingerprinting"], "good_for" => ["file integrity verification (non-cryptographic)", "legacy compatibility", "deduplication"], "avoid_for" => ["security", "passwords", "signatures", "message authentication"], "pros" => ["fast", "widely available", "simple"], "cons" => ["collision attacks trivial", "preimage attacks possible", "broken for cryptography"], "difficulty" => 1, "security" => 1, "quantum_impact" => "Already broken; quantum attacks obsolete.", "post_quantum_status" => 1, "example" => ["scenario" => "File integrity check (non-security)", "input" => ["file_data" => "release-1.2.3.tar.gz content buffer"], "output" => ["hash" => "5d41402abc4b2a76b9719d911017c592"]], "flow" => ["padding", "64 rounds", "compression", "digest"], "related" => ["md2", "md4", "sha1"]],
        ["algo" => 38, "uuid" => "4e223c", "name" => "sha0", "type" => "hash", "status" => "broken", "title" => "SHA-0 (SHA)", "description_md" => "SHA-0 was the original Secure Hash Algorithm released by NSA in 1993. It outputs 160 bits (20 bytes). Withdrawn shortly after release due to a flaw, replaced by SHA-1. The flaw allowed differential cryptanalysis attacks. Never widely deployed due to quick withdrawal. Extremely rare in the wild, mainly of historical interest. The vulnerability that led to its withdrawal hinted at weaknesses that would later compromise SHA-1. SHA-0 is never recommended and has no modern use case. Study only for understanding cryptographic evolution and NSA algorithm design from that era.", "mental_model" => "Prototype bridge that was demolished before opening.", "purpose" => ["historical reference"], "good_for" => ["studying cryptographic history"], "avoid_for" => ["everything else"], "pros" => ["none"], "cons" => ["flaw found immediately", "never deployed", "collision attacks"], "difficulty" => 1, "security" => 1, "quantum_impact" => "Already broken; design flaw predates quantum.", "post_quantum_status" => 1, "example" => ["scenario" => "Historical documentation only", "input" => ["message" => "example"], "output" => ["hash" => "f2d72b1e6c1046b627099ef4909a55b410d4e4ae"]], "flow" => ["padding", "80 rounds", "compress", "160-bit digest"], "related" => ["sha1", "sha2"]],
        ["algo" => 39, "uuid" => "c3d5dd", "name" => "sha1", "type" => "hash", "status" => "broken", "title" => "SHA-1", "description_md" => "SHA-1 produces 160 bits (20 bytes) of hash output. Designed by NSA in 1995, it became the gold standard for two decades. Collision attacks were theoretically possible by 2005, but practical attacks were not demonstrated until 2017 when SHAttered proved collisions could be generated in hours. Most browsers deprecated SHA-1 in TLS certificates around 2017. Still prevalent in Git commits, legacy systems, and old digital signatures. For new code, never use SHA-1 for security purposes. Legacy systems using SHA-1 in TLS or code signing should migrate urgently. Safe only for non-security contexts like Git storage or version control.", "mental_model" => "Reliable vault from 1995 that was finally cracked in 2017.", "purpose" => ["compute hash", "legacy security"], "good_for" => ["git commits", "legacy compatibility", "non-security checksums"], "avoid_for" => ["tls certificates", "code signing", "security applications"], "pros" => ["widely supported", "20-byte output", "simple"], "cons" => ["collision attacks practical", "broken for security", "deprecated in TLS"], "difficulty" => 1, "security" => 2, "quantum_impact" => "Grover reduces 160-bit to ~80-bit security.", "post_quantum_status" => 1, "example" => ["scenario" => "Git commit hash verification", "input" => ["commit_data" => "tree abc123\nparent def456\nauthor user@example.com\n\nCommit message"], "output" => ["hash" => "aaf4c61ddcc5e8a2dabede0f3b482cd9aea9434d"]], "flow" => ["padding", "80 rounds", "compress", "160-bit digest"], "related" => ["sha0", "sha2", "sha3"]],
        ["algo" => 75, "uuid" => "635392", "name" => "gost-r-34.11-94", "type" => "hash", "status" => "legacy", "title" => "GOST R 34.11-94", "description_md" => "Russian cryptographic hash standard producing 256 bits (32 bytes). Designed in the 1990s for Russian government use. Similar structure to MD5/SHA-1 but with different constants. Used in Russian cryptographic infrastructure and embedded in GOST signatures. Security margins are lower than SHA-2/SHA-3; collision resistance is claimed at 128 bits rather than 256. Replaced by GOST R 34.11-2012 (Streebog). Only relevant for Russian government system compatibility or legacy Russian cryptographic software. Not recommended for new applications outside Russian infrastructure.", "mental_model" => "Soviet-era cipher with unique design philosophy.", "purpose" => ["compute hash", "russian compatibility"], "good_for" => ["russian government systems", "legacy russian software"], "avoid_for" => ["new applications", "international standards"], "pros" => ["256-bit output", "russian standard"], "cons" => ["lower security margin", "replaced by streebog", "limited international adoption"], "difficulty" => 2, "security" => 2, "quantum_impact" => "Grover attack reduces 256-bit to ~128-bit.", "post_quantum_status" => 1, "example" => ["scenario" => "Russian legacy document signature", "input" => ["document" => "Государственное соглашение"], "output" => ["hash" => "ce85b99cc46752fffee35cab9a7b0278abb4c1d7cb516f510eda54cb627dccf60"]], "flow" => ["russian sbox", "64 rounds", "256-bit digest"], "related" => ["streebog256", "streebog512"]],
        ["algo" => 78, "uuid" => "053425", "name" => "ripemd128", "type" => "hash", "status" => "legacy", "title" => "RIPEMD-128", "description_md" => "RIPEMD-128 is a 128-bit hash function from 1996 using parallel compression. Designed as a faster alternative to RIPEMD with 128-bit output. While faster than the original RIPEMD, it provides only 128-bit security, making it unsuitable for long-term security needs. Rarely used; RIPEMD-160 is the more common variant. Has not been actively broken, but 128-bit digests are considered insufficient for modern security requirements. Some legacy systems and old cryptocurrency implementations may use it. Not recommended for new applications; use RIPEMD-160 or better alternatives like SHA-2 or SHA-3.", "mental_model" => "Compact but shallow security container.", "purpose" => ["compute hash", "legacy compatibility"], "good_for" => ["legacy cryptocurrency", "old financial systems"], "avoid_for" => ["new applications", "long-term security"], "pros" => ["128-bit output", "fast", "simple"], "cons" => ["128-bit security insufficient", "rarely used", "replaced by ripemd160"], "difficulty" => 1, "security" => 2, "quantum_impact" => "Grover reduces 128-bit to ~64-bit.", "post_quantum_status" => 1, "example" => ["scenario" => "Legacy Bitcoin address derivation", "input" => ["pubkey" => "02c6047f9441ed7d6d3045406e95c07cd85c778e4b8cef3ca7d5480482e496ea7e"], "output" => ["hash" => "62e907b15cbf27d5425399fbf6f0fb50ebb88f18"]], "flow" => ["padding", "64 rounds parallel", "128-bit digest"], "related" => ["ripemd160", "ripemd256", "ripemd320"]],
        ["algo" => 79, "uuid" => "a99f05", "name" => "ripemd160", "type" => "hash", "status" => "legacy", "title" => "RIPEMD-160", "description_md" => "RIPEMD-160 produces 160 bits (20 bytes) using parallel left/right compression paths. Designed in 1996 as improvement over RIPEMD-128. Provides 160-bit security with good cryptanalysis resistance. Primary use is Bitcoin address generation: Bitcoin uses RIPEMD-160 after SHA-256 to create 160-bit addresses. Because Bitcoin uses it extensively, RIPEMD-160 remains relevant despite age. Not broken, but 160-bit output is modest by modern standards. Performance is good. Critical for Bitcoin compatibility and legacy systems using it. For new applications, prefer SHA-256 or BLAKE2 unless Bitcoin integration required.", "mental_model" => "Reliable Bitcoin address vault.", "purpose" => ["compute hash", "bitcoin addresses"], "good_for" => ["bitcoin", "cryptocurrency", "legacy systems"], "avoid_for" => ["new non-bitcoin applications"], "pros" => ["160-bit output", "bitcoin standard", "parallel design", "good performance"], "cons" => ["160-bit digest modest", "age", "specialized use"], "difficulty" => 2, "security" => 3, "quantum_impact" => "Grover reduces 160-bit to ~80-bit.", "post_quantum_status" => 1, "example" => ["scenario" => "Bitcoin address generation", "input" => ["pubkey_sha256" => "600ffe422b4046d7d6d3045406e95c07cd85c778e4b8cef3ca7d5480482e496ea7e"], "output" => ["address_hash" => "62e907b15cbf27d5425399fbf6f0fb50ebb88f18"]], "flow" => ["padding", "80 rounds left/right parallel", "160-bit digest"], "related" => ["ripemd128", "ripemd256", "sha256"]],
        ["algo" => 80, "uuid" => "ae3273", "name" => "ripemd256", "type" => "hash", "status" => "legacy", "title" => "RIPEMD-256", "description_md" => "RIPEMD-256 is a 256-bit variant using parallel compression paths. Provides stronger security than RIPEMD-160 with 256-bit output. Designed with the same philosophy as RIPEMD-160: two parallel compression chains. RIPEMD-256 has not been broken, but it is rarely used compared to SHA-256 and other modern alternatives. Performance is good but offers no advantage over SHA-256. Mainly encountered in legacy systems that chose RIPEMD over SHA-family algorithms. Not recommended for new code. Use SHA-256 or BLAKE2b for modern applications requiring 256-bit security.", "mental_model" => "Solid but unfashionable security container.", "purpose" => ["compute hash"], "good_for" => ["legacy system compatibility"], "avoid_for" => ["new applications"], "pros" => ["256-bit output", "parallel design", "not broken"], "cons" => ["rarely used", "overshadowed by sha256", "no advantage"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Grover reduces 256-bit to ~128-bit.", "post_quantum_status" => 1, "example" => ["scenario" => "Legacy checksum archive", "input" => ["data" => "archive_2015_backup.tar.gz content stream"], "output" => ["hash" => "7fd2a0ae9485fe2d8b87fa4c7ec57ed95ed6bf7d48819d0fdbe4f7a97f8c8d1d"]], "flow" => ["padding", "128 rounds parallel", "256-bit digest"], "related" => ["ripemd128", "ripemd160", "ripemd320", "sha256"]],
        ["algo" => 81, "uuid" => "2202a0", "name" => "ripemd320", "type" => "hash", "status" => "legacy", "title" => "RIPEMD-320", "description_md" => "RIPEMD-320 produces 320 bits (40 bytes) using five parallel compression branches. Provides extended security with 320-bit output. Even less commonly used than RIPEMD-256. Five parallel paths make it more complex than RIPEMD-160 or RIPEMD-256. No significant security advantage over SHA-512 with added complexity. Never broken but almost never selected for new systems. Encountered primarily in academic cryptography or systems that standardized on the full RIPEMD family. Modern applications should use SHA-512 or BLAKE2 instead.", "mental_model" => "Overbuilt security apparatus with five parallel locks.", "purpose" => ["compute hash"], "good_for" => ["theoretical study", "legacy academic systems"], "avoid_for" => ["production applications"], "pros" => ["320-bit output", "five parallel paths", "not broken"], "cons" => ["rarely used", "complex", "no advantage over sha512"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Grover reduces 320-bit to ~160-bit.", "post_quantum_status" => 1, "example" => ["scenario" => "Academic cryptography exercise", "input" => ["message" => "Test message for parallel compression study"], "output" => ["hash" => "aa8c1d7f8c8f8f5f8f8f5f8f8f8f5f8f8f8f5f8f8f8f5f8f8f8f5f8f8f5f8f8f5f8f"]], "flow" => ["padding", "160 rounds five parallel", "320-bit digest"], "related" => ["ripemd128", "ripemd160", "ripemd256"]],
        ["algo" => 82, "uuid" => "0c6fd0", "name" => "tiger", "type" => "hash", "status" => "legacy", "title" => "Tiger", "description_md" => "Tiger is a 192-bit hash designed by Ross Anderson and Eli Biham in 1996 specifically optimized for 64-bit processors. Offers 192-bit output (24 bytes). Tiger was innovative for its era but is rarely used today. No practical attacks exist, but 192-bit output is an awkward size between 160 and 256 bits. Performance is excellent on 64-bit systems, but modern processors make this advantage marginal. Found in legacy document management systems and old integrity verification tools. Not broken, but superseded by SHA-2 and SHA-3. New applications should use SHA-256 or BLAKE2 unless Tiger compatibility is required.", "mental_model" => "Fast 64-bit sprinter from the 1990s.", "purpose" => ["compute hash", "legacy integrity"], "good_for" => ["legacy document systems", "old file verification"], "avoid_for" => ["new applications"], "pros" => ["192-bit output", "64-bit optimized", "fast", "not broken"], "cons" => ["awkward output size", "rarely used", "outdated"], "difficulty" => 2, "security" => 3, "quantum_impact" => "Grover reduces 192-bit to ~96-bit.", "post_quantum_status" => 1, "example" => ["scenario" => "Legacy file archival verification", "input" => ["file" => "document_1995.pdf content buffer"], "output" => ["hash" => "2aa10ca8cefc36f5787d69d47f30cbecbec2e6e5a1e0f6af"]], "flow" => ["padding", "24 rounds", "192-bit digest"], "related" => ["sha1", "sha256"]],
        ["algo" => 83, "uuid" => "2c7eee", "name" => "whirlpool", "type" => "hash", "status" => "legacy", "title" => "Whirlpool", "description_md" => "Whirlpool is a 512-bit cryptographic hash designed by Vincent Rijmen and Paulo Barreto in 2000. Based on AES-like block cipher structure. Produces 64 bytes of output. Whirlpool is not broken and offers strong security margins. It appeared in some Brazilian cryptographic standards and legacy applications. Performance is adequate but not exceptional on modern hardware. Rarely selected for new systems; SHA-512 is preferred. No known cryptanalysis weaknesses. Useful for understanding block-cipher-based hash design. Some legacy systems in Brazil or older commercial software might use it. Prefer SHA-512 or BLAKE2 for new applications.", "mental_model" => "Solid waterwheel cipher from 2000.", "purpose" => ["compute hash"], "good_for" => ["legacy brazilian systems", "understanding block-cipher hashing"], "avoid_for" => ["new applications"], "pros" => ["512-bit output", "not broken", "AES-like design"], "cons" => ["rarely used", "slower than sha512", "niche adoption"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Grover reduces 512-bit to ~256-bit.", "post_quantum_status" => 1, "example" => ["scenario" => "Legacy Brazilian document signature", "input" => ["document" => "Contrato de servicos profissionais 2008"], "output" => ["hash" => "19fa61d75522e1b7ad3e59e10ef1d4e35e7b2c2e8c6b67a4f7d5c6e5a4f3e2d1a0b9c8d7e6f5a4b3c2d1e0f9a8b7c6d5e4f"]], "flow" => ["mimc-like compression", "80 rounds", "512-bit digest"], "related" => ["sha512", "blake2b"]],
        ["algo" => 84, "uuid" => "b8611f", "name" => "has160", "type" => "hash", "status" => "legacy", "title" => "HAS-160", "description_md" => "HAS-160 is a 160-bit hash designed in South Korea in 1998. Produces 20 bytes of output. Part of the CIST (Cryptographic Internet Standards and Technology) standard family. HAS-160 uses a similar design to SHA-1 but with different constants. Never widely deployed outside South Korean systems. No known practical attacks, but 160-bit security is dated. South Korean government used it in official standards before transitioning to SHA family. Rarely encountered in international systems. Only relevant for South Korean legacy system compatibility. Modern systems should use SHA-256 or better.", "mental_model" => "Regional security standard from Seoul.", "purpose" => ["compute hash", "korean compatibility"], "good_for" => ["south korean legacy systems"], "avoid_for" => ["new applications"], "pros" => ["160-bit output", "korean standard"], "cons" => ["regional adoption only", "160-bit dated", "replaced by sha"], "difficulty" => 1, "security" => 2, "quantum_impact" => "Grover reduces 160-bit to ~80-bit.", "post_quantum_status" => 1, "example" => ["scenario" => "Legacy Korean government document", "input" => ["document" => "대한민국 정부 공문서"], "output" => ["hash" => "a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6e7f8a9b"]], "flow" => ["padding", "80 rounds korean sbox", "160-bit digest"], "related" => ["sha1"]],
        ["algo" => 85, "uuid" => "4abc38", "name" => "nt-hash", "type" => "hash", "status" => "broken", "title" => "NT Hash (NTLM)", "description_md" => "NT Hash (part of NTLM) is used by Windows for password hashing. Not a standard cryptographic hash; it's MD4 applied to UTF-16LE encoded password. Produces 128 bits (16 bytes). Windows uses this for local authentication and domain login via NTLM. Critically broken: no salt, MD4 is broken, rainbow tables are trivial. Modern Windows systems should use Kerberos or modern credential systems. NTLMv2 improved the protocol layer but still uses weak underlying hashing. Every Windows password hash leaked is easily cracked. Used only for backward compatibility with ancient systems and Windows 95/98/NT 4.0 era clients. Never use for new applications; upgrade to modern authentication.", "mental_model" => "Padlock from Windows 95 that anyone with a crowbar can open.", "purpose" => ["windows authentication legacy"], "good_for" => ["understanding why legacy is broken"], "avoid_for" => ["everything modern"], "pros" => ["widely understood"], "cons" => ["no salt", "md4 based", "trivially crackable", "security disaster"], "difficulty" => 1, "security" => 1, "quantum_impact" => "Already broken; quantum irrelevant.", "post_quantum_status" => 1, "example" => ["scenario" => "Legacy Windows domain password (demonstrating vulnerability)", "input" => ["password" => "P@ssw0rd2003", "encoding" => "utf16le"], "output" => ["nt_hash" => "209c6174da490caeb422f3fa5a7ae634"]], "flow" => ["utf16le encode", "md4 hash", "128-bit result"], "related" => ["md4", "ntlmv1", "ntlmv2"]],
        ["algo" => 86, "uuid" => "25efef", "name" => "lm-hash", "type" => "hash", "status" => "broken", "title" => "LM Hash (LANMAN)", "description_md" => "LM Hash (LAN Manager) from Windows for password storage. Critically flawed: uppercase password, split into 7-character halves, each half DES encrypted separately. Each half can be cracked independently. No salt. Produces 16 bytes. Used in Windows 3.11, Windows 95, NT through Windows 2000 for backward compatibility. Completely broken since the 1990s. Rainbow tables crack it instantly. Modern Windows disabled LM hash in Windows Vista SP1+, but legacy systems still use it. Penetration testers exploit it routinely. Never use for security. Upgrade any system still using LM hash. Historical importance only as worst-practice example.", "mental_model" => "Combination lock designed with digits that repeat every 7 positions.", "purpose" => ["legacy authentication", "cracking exercise"], "good_for" => ["understanding what never to do"], "avoid_for" => ["everything"], "pros" => ["historical significance"], "cons" => ["completely broken", "no salt", "7-char halves", "split key space", "instantly crackable"], "difficulty" => 1, "security" => 0, "quantum_impact" => "Already trivially broken.", "post_quantum_status" => 0, "example" => ["scenario" => "Ancient Windows 95 password (for study only)", "input" => ["password" => "SECRETPASS"], "output" => ["lm_hash" => "e52cac67419a6a9a42f8b3674674327612da26eeca8d8a3e"]], "flow" => ["uppercase", "pad to 14", "split halves", "des encrypt", "56-bit keys"], "related" => ["ntlm", "des"]],
        ["algo" => 87, "uuid" => "674ccc", "name" => "md6", "type" => "hash", "status" => "legacy", "title" => "MD6", "description_md" => "MD6 is an AES-like tree hash designed by Ron Rivest for SHA-3 competition (2008). Supports variable output lengths (1-512 bits). Uses tree hashing for parallelism on multi-core systems. MD6 was rejected from SHA-3 due to complexity and insufficient analysis. No major weaknesses found, but the design was considered over-engineered. Never standardized or widely adopted. Appeared only in specialized research and some academic projects. Tree structure is interesting for parallel hashing on many-core systems. Study for understanding alternative hash paradigms. Modern applications use SHA-3 or BLAKE3 instead.", "mental_model" => "Overdesigned parallel tree from a competition that didn't win.", "purpose" => ["parallel hashing", "research"], "good_for" => ["studying tree hash designs", "academic research"], "avoid_for" => ["production systems"], "pros" => ["tree structure", "variable output", "parallel friendly"], "cons" => ["rejected from sha3", "complex", "never standardized"], "difficulty" => 3, "security" => 3, "quantum_impact" => "Grover reduces security by sqrt.", "post_quantum_status" => 2, "example" => ["scenario" => "Parallel tree hash of large file (research)", "input" => ["data" => "massive_dataset_1gb chunk"], "output" => ["hash_256" => "a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6e7f8a9b0c1d2e3f4a5b6c7d8e9f0a1"]], "flow" => ["tree nodes", "parallel compression", "variable output"], "related" => ["blake3", "sha3"]],
        ["algo" => 88, "uuid" => "2f0f17", "name" => "radio-gatun", "type" => "hash", "status" => "legacy", "title" => "RadioGatun", "description_md" => "RadioGatun is a sponge-like hash and stream cipher design by Guido Bertoni and others (2006). Related to Keccak (SHA-3 basis). Uses a 58-word belt and 3-word mill architecture. Variable output length supported. Submitted to SHA-3 competition but not selected. No practical attacks found, but design is academic and specialized. Mainly studied in cryptography research for alternative sponge constructions. Used in few production systems. Tree hashing variant exists for parallelism. Understanding RadioGatun helps learning sponge-based hash design. Use SHA-3 or BLAKE3 for modern applications.", "mental_model" => "Experimental sponge architecture that lost the competition.", "purpose" => ["research", "alternative sponge"], "good_for" => ["learning sponge design", "cryptographic research"], "avoid_for" => ["production applications"], "pros" => ["sponge design", "variable output", "parallel variant"], "cons" => ["academic", "not standardized", "rarely used"], "difficulty" => 3, "security" => 3, "quantum_impact" => "Sponge resistance: Grover reduces by sqrt.", "post_quantum_status" => 2, "example" => ["scenario" => "Research sponge hash output", "input" => ["input" => "radiogatun research example"], "output" => ["hash" => "c1c2c3c4c5c6c7c8c9c0c1c2c3c4c5c6c7c8c9c0c1c2c3c4c5c6c7c8c9c0"]], "flow" => ["sponge absorb", "belt rotation", "mill transform", "squeeze"], "related" => ["keccak", "sha3"]],
        ["algo" => 89, "uuid" => "fa3b94", "name" => "groestl", "type" => "hash", "status" => "legacy", "title" => "Groestl", "description_md" => "Groestl is a hash function designed by Gauravaram et al. (2010) for SHA-3 competition. Uses AES-like core with compression in both forward and backward directions. Supports 256 and 512-bit output. Strong cryptanalysis, no weaknesses found. Reached SHA-3 finalist round (top 5) but was not selected. Wide adoption never occurred; SHA-3 (Keccak) was preferred. Groestl offers good security but more complex than necessary. Still used in some niche applications and cryptocurrency projects. Understanding Groestl provides insight into AES-based hash design. Modern code should use SHA-3 or BLAKE2/BLAKE3 instead.", "mental_model" => "Finalists' trophy from the SHA-3 competition.", "purpose" => ["compute hash", "research"], "good_for" => ["some cryptocurrency systems", "studying aes-based hashing"], "avoid_for" => ["new general applications"], "pros" => ["strong cryptanalysis", "256/512-bit output", "aes structure familiar"], "cons" => ["complex", "not standardized", "sha3 preferred"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Grover reduces security by sqrt.", "post_quantum_status" => 2, "example" => ["scenario" => "SHA-3 finalist hash example", "input" => ["message" => "Groestl SHA3 finalist round"], "output" => ["hash_256" => "f0a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6e7f8a9b0c1d2e3f4a5b6c7d8e9"]], "flow" => ["padding", "compression forward", "compression backward", "256-bit digest"], "related" => ["sha3", "blake2"]],
        ["algo" => 90, "uuid" => "b75340", "name" => "jh", "type" => "hash", "status" => "legacy", "title" => "JH", "description_md" => "JH is a hash function designed by Hongjun Wu for SHA-3 competition. Uses linear transformation over GF(2) with S-box based compression. Supports 224, 256, 384, and 512-bit output. Reached SHA-3 finalist round (top 5). Strong security analysis. No practical attacks found. Complex design with heavy use of bitwise operations. JH performs well on hardware. Limited adoption in production; SHA-3 became standard instead. Used in some embedded systems and ASIC designs. Study for understanding GF(2) based hash design. New applications should prefer SHA-3 (Keccak) or BLAKE3.", "mental_model" => "Hardware specialist runner-up from SHA-3.", "purpose" => ["compute hash", "embedded systems"], "good_for" => ["embedded crypto research", "hardware implementations"], "avoid_for" => ["general applications"], "pros" => ["hardware friendly", "256/512-bit output", "strong analysis"], "cons" => ["complex design", "not standardized", "sha3 preferred"], "difficulty" => 3, "security" => 4, "quantum_impact" => "Grover reduces security by sqrt.", "post_quantum_status" => 2, "example" => ["scenario" => "Embedded system hash", "input" => ["sensor_data" => "0xa1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6"], "output" => ["hash_256" => "b8a9d7c6e5f4a3b2c1d0e9f8a7b6c5d4e3f2a1b0c9d8e7f6a5b4c3d2e1f0"]], "flow" => ["padding", "linear transform", "sbox compress", "256-bit"], "related" => ["sha3", "blake3"]],
        ["algo" => 91, "uuid" => "240540", "name" => "cubehash", "type" => "hash", "status" => "legacy", "title" => "CubeHash", "description_md" => "CubeHash is a hash function with simple structure designed by Daniel J. Bernstein for SHA-3 competition. Uses cube-like state with identical round functions. Supports 224, 256, 384, and 512-bit output. Designed for simplicity and elegance. Good cryptanalysis, no weaknesses found. Did not reach SHA-3 finals but has academic interest. Simple design makes it easy to implement and analyze. CubeHash rounds are numerous (10+ optional) but lightweight. Rarely used in production. Some embedded systems explored it. Study for understanding minimalist hash design. Use SHA-3 or BLAKE3 for modern applications.", "mental_model" => "Elegant cube-based hash from a design competition.", "purpose" => ["compute hash", "research"], "good_for" => ["understanding simple hash design", "embedded systems study"], "avoid_for" => ["production applications"], "pros" => ["simple elegant design", "easy to analyze", "variable output"], "cons" => ["not selected for sha3", "rarely used", "slow per round"], "difficulty" => 2, "security" => 3, "quantum_impact" => "Grover reduces security by sqrt.", "post_quantum_status" => 2, "example" => ["scenario" => "Simple cube hash example", "input" => ["message" => "cubehash test"], "output" => ["hash_256" => "e0f0a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6e7f8a9b0c1d2e3f4a5b6c7d8"]], "flow" => ["padding", "cube rotate", "identical rounds", "256-bit digest"], "related" => ["sha3", "blake3"]],
        ["algo" => 92, "uuid" => "cbc5a6", "name" => "echo", "type" => "hash", "status" => "legacy", "title" => "Echo", "description_md" => "Echo is a hash function using AES round function designed by Daniele Bernstein et al. for SHA-3 competition. Supports 224, 256, 384, and 512-bit output. Uses AES encryption in compression function. Wide pipe approach (double rate). Did not reach SHA-3 finals. Strong cryptanalysis conducted. Performance on AES-capable hardware is good. Echo is complex and rarely deployed. Some systems explored it for AES integration. Understanding Echo shows AES-based alternative designs. Production systems should use SHA-3 or BLAKE2.", "mental_model" => "AES-based finalist who didn't make the cut.", "purpose" => ["compute hash", "aes integration"], "good_for" => ["studying aes hash design"], "avoid_for" => ["production systems"], "pros" => ["aes core", "256/512-bit", "wide pipe"], "cons" => ["not standardized", "complex", "rarely used"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Grover reduces security by sqrt.", "post_quantum_status" => 2, "example" => ["scenario" => "Echo hash example", "input" => ["data" => "echo aes hash test"], "output" => ["hash_256" => "f1a2b3c4d5e6f7a8b9c0d1e2f3a4b5c6d7e8f9a0b1c2d3e4f5a6b7c8d9e0"]], "flow" => ["aes rounds", "wide compression", "256-bit digest"], "related" => ["sha3", "groestl"]],
        ["algo" => 93, "uuid" => "a992fc", "name" => "simd", "type" => "hash", "status" => "legacy", "title" => "SIMD", "description_md" => "SIMD is a hash function using parallel SIMD design by Jean-Philippe Aumasson et al. for SHA-3 competition. Supports 256 and 512-bit output. Uses SIMD operations for parallelism on CPUs. Two-round compression strategy. Did not reach SHA-3 finals. Good performance on SIMD-capable hardware (SSE2, AVX). Design is interesting but complex. Limited deployment in production. Study for understanding SIMD-based hash design and CPU optimization. Modern systems prefer BLAKE2 which also uses SIMD but is simpler. Use SHA-3 or BLAKE2 for new applications.", "mental_model" => "SIMD speedster from SHA-3 competition.", "purpose" => ["compute hash", "parallel processing"], "good_for" => ["studying simd hash optimization"], "avoid_for" => ["production systems"], "pros" => ["simd optimized", "fast on sse2/avx", "parallel friendly"], "cons" => ["complex design", "not standardized", "blake2 preferred"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Grover reduces security by sqrt.", "post_quantum_status" => 2, "example" => ["scenario" => "SIMD parallel hash", "input" => ["vector_data" => "[0xa1b2c3d4, 0xe5f6a7b8, 0xc9d0e1f2]"], "output" => ["hash_256" => "d0e1f2a3b4c5d6e7f8a9b0c1d2e3f4a5b6c7d8e9f0a1b2c3d4e5f6a7b8c9"]], "flow" => ["simd parallel rounds", "compression", "256-bit"], "related" => ["blake2", "sha3"]],
        ["algo" => 94, "uuid" => "2a367a", "name" => "fugue", "type" => "hash", "status" => "legacy", "title" => "Fugue", "description_md" => "Fugue is a hash function using AES core designed by Shai Halevi et al. for SHA-3 competition. Supports 224, 256, 384, and 512-bit output. Uses AES encryption in compression with 16-word state (128 bits of AES). Did not reach SHA-3 finals. Solid cryptanalysis, no weaknesses. Design is comprehensive and optimized. Performance on AES hardware is good. Very limited deployment. Some systems explored it. Understanding Fugue shows another AES-based hash design approach. Production systems should use SHA-3 (Keccak) or BLAKE2 which are standardized.", "mental_model" => "Another AES-based SHA-3 contender.", "purpose" => ["compute hash", "research"], "good_for" => ["studying aes hash variants"], "avoid_for" => ["production applications"], "pros" => ["aes core", "comprehensive design", "256/512-bit"], "cons" => ["not standardized", "rarely used", "sha3 preferred"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Grover reduces security by sqrt.", "post_quantum_status" => 2, "example" => ["scenario" => "Fugue hash", "input" => ["message" => "fugue aes hash"], "output" => ["hash_256" => "c9d8e7f6a5b4c3d2e1f0a9b8c7d6e5f4a3b2c1d0e9f8a7b6c5d4e3f2a1b0"]], "flow" => ["aes compression", "16-word state", "256-bit output"], "related" => ["sha3", "groestl", "echo"]],
        ["algo" => 95, "uuid" => "ff851d", "name" => "hamsi", "type" => "hash", "status" => "legacy", "title" => "Hamsi", "description_md" => "Hamsi is a hash function designed by Ozdemir and Varici for SHA-3 competition. Supports 224, 256, 384, and 512-bit output. Uses block cipher-based compression function. Did not reach SHA-3 finals. Design is straightforward with good cryptanalysis. No practical attacks. Performance is moderate. Very limited production use. Mainly academic interest. Understanding Hamsi helps learning traditional block-cipher-based hash design. Modern applications should use SHA-3 or BLAKE2.", "mental_model" => "Turkish crypto entry from SHA-3 competition.", "purpose" => ["compute hash", "research"], "good_for" => ["studying block cipher hashing"], "avoid_for" => ["production systems"], "pros" => ["block cipher based", "256/512-bit", "straightforward"], "cons" => ["not standardized", "rarely used"], "difficulty" => 1, "security" => 3, "quantum_impact" => "Grover reduces security by sqrt.", "post_quantum_status" => 2, "example" => ["scenario" => "Hamsi hash", "input" => ["data" => "hamsi test"], "output" => ["hash_256" => "e1f2a3b4c5d6e7f8a9b0c1d2e3f4a5b6c7d8e9f0a1b2c3d4e5f6a7b8c9d0"]], "flow" => ["block cipher compress", "256-bit output"], "related" => ["sha3", "blake2"]],
        ["algo" => 96, "uuid" => "abd5ff", "name" => "luffa", "type" => "hash", "status" => "legacy", "title" => "Luffa", "description_md" => "Luffa is a hash function with tree structure designed by Hitachi researchers for SHA-3 competition. Supports 224, 256, 384, and 512-bit output. Uses three independent permutation branches that merge. Did not reach SHA-3 finals. Good security analysis. No practical attacks. Parallelism at algorithm level. Very limited deployment. Some embedded systems studied it. Understanding Luffa provides insight into multi-branch hash design. Production systems should use SHA-3 (Keccak) or BLAKE3 which are standardized.", "mental_model" => "Three-branch Hitachi design from SHA-3.", "purpose" => ["compute hash", "parallel research"], "good_for" => ["studying multi-branch designs"], "avoid_for" => ["production applications"], "pros" => ["tree structure", "parallel friendly", "256/512-bit"], "cons" => ["not standardized", "rarely used"], "difficulty" => 2, "security" => 3, "quantum_impact" => "Grover reduces security by sqrt.", "post_quantum_status" => 2, "example" => ["scenario" => "Luffa tree hash", "input" => ["message" => "luffa parallel hash"], "output" => ["hash_256" => "f6a7b8c9d0e1f2a3b4c5d6e7f8a9b0c1d2e3f4a5b6c7d8e9f0a1b2c3d4e5"]], "flow" => ["three branches", "parallel merge", "256-bit output"], "related" => ["sha3", "blake3"]],
        ["algo" => 97, "uuid" => "2ff331", "name" => "shabal", "type" => "hash", "status" => "legacy", "title" => "SHAbal", "description_md" => "SHAbal is a hash function by Emmanuel Bresson et al. for SHA-3 competition. Supports 224, 256, 384, and 512-bit output. Uses wide-pipe architecture (1024-bit state). Did not reach SHA-3 finals. Solid cryptanalysis, no weaknesses found. Design emphasizes wide state for security margins. Performance is good. Very limited production deployment. Mainly academic interest. Understanding SHAbal shows wide-pipe design philosophy. Modern applications should use SHA-3 or BLAKE2.", "mental_model" => "Wide-pipe architect from SHA-3 competition.", "purpose" => ["compute hash", "research"], "good_for" => ["studying wide-pipe designs"], "avoid_for" => ["production systems"], "pros" => ["wide 1024-bit state", "good margins", "256/512-bit"], "cons" => ["not standardized", "rarely used"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Grover reduces security by sqrt.", "post_quantum_status" => 2, "example" => ["scenario" => "SHAbal hash", "input" => ["message" => "shabal wide pipe"], "output" => ["hash_256" => "a4b5c6d7e8f9a0b1c2d3e4f5a6b7c8d9e0f1a2b3c4d5e6f7a8b9c0d1e2f3"]], "flow" => ["1024-bit state", "wide compression", "256-bit digest"], "related" => ["sha3", "blake2"]],
        ["algo" => 98, "uuid" => "5556f4", "name" => "bmw", "type" => "hash", "status" => "legacy", "title" => "BMW", "description_md" => "BMW (Blue Midnight Wish) is a hash function by Danilo Gligoroski et al. for SHA-3 competition. Supports 224, 256, 384, and 512-bit output. Uses large internal state (1024 or 2048 bits). Did not reach SHA-3 finals. Good cryptanalysis. No practical attacks. Large state provides security margins. Performance is moderate. Very limited production use. Rarely encountered. Understanding BMW shows large-state design approach. Modern applications should use SHA-3 (Keccak) or BLAKE3 which are standardized.", "mental_model" => "Midnight wish from SHA-3 competition.", "purpose" => ["compute hash", "research"], "good_for" => ["studying large-state designs"], "avoid_for" => ["production applications"], "pros" => ["large state", "security margins", "256/512-bit"], "cons" => ["not standardized", "rarely used"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Grover reduces security by sqrt.", "post_quantum_status" => 2, "example" => ["scenario" => "BMW hash", "input" => ["data" => "bmw large state hash"], "output" => ["hash_256" => "b7c8d9e0f1a2b3c4d5e6f7a8b9c0d1e2f3a4b5c6d7e8f9a0b1c2d3e4f5a6"]], "flow" => ["1024-bit state", "compression", "256-bit output"], "related" => ["sha3", "blake2"]],
        ["algo" => 99, "uuid" => "d85d8d", "name" => "shavite3", "type" => "hash", "status" => "legacy", "title" => "SHAvite-3", "description_md" => "SHAvite-3 is a hash function with AES core by Eli Biham and Orr Dunkelman for SHA-3 competition. Supports 224, 256, 384, and 512-bit output. Uses AES round functions in compression. Reached SHA-3 finalist round (top 5). Strong cryptanalysis. No practical attacks found. Performance on AES-capable hardware is excellent. Design is complex and comprehensive. Limited deployment despite finalists status; SHA-3 was preferred. Some systems explored it. Understanding SHAvite-3 shows complex AES-based design. Production systems should use SHA-3 or BLAKE2 which are standardized.", "mental_model" => "AES finalist from SHA-3 top 5.", "purpose" => ["compute hash", "aes research"], "good_for" => ["studying advanced aes hashing"], "avoid_for" => ["general applications"], "pros" => ["aes finalist", "strong analysis", "aes hardware fast"], "cons" => ["complex", "not standardized", "sha3 preferred"], "difficulty" => 3, "security" => 4, "quantum_impact" => "Grover reduces security by sqrt.", "post_quantum_status" => 2, "example" => ["scenario" => "SHAvite-3 finalist hash", "input" => ["message" => "shavite3 aes finalist"], "output" => ["hash_256" => "c5d6e7f8a9b0c1d2e3f4a5b6c7d8e9f0a1b2c3d4e5f6a7b8c9d0e1f2a3b4"]], "flow" => ["aes compression", "256-bit output"], "related" => ["sha3", "groestl"]],
    ],
    "active" => [
        ["algo" => 40, "uuid" => "973e62", "name" => "sha224", "type" => "hash", "status" => "active", "title" => "SHA-224", "description_md" => "SHA-224 is a truncated version of SHA-256 producing 224 bits (28 bytes) of output. Part of SHA-2 family designed by NSA. Uses same compression function as SHA-256 but with different initialization values. Provides 224-bit security, suitable for legacy systems that can't store 256-bit hashes. Used for compatibility where 256-bit is too large. Good cryptanalysis resistance. No practical attacks. Grover algorithm would reduce security to 112 bits in quantum era. Suitable for general-purpose hashing where 224 bits suffice. Most new applications prefer SHA-256 for simplicity. Still secure and acceptable.", "mental_model" => "Shorter version of the reliable 256-bit vault.", "purpose" => ["compute hash", "legacy 224-bit needs"], "good_for" => ["compatibility", "space-constrained systems"], "avoid_for" => ["none; it's secure"], "pros" => ["sha2 family", "224-bit output", "fast", "widely supported"], "cons" => ["224-bit output may be limiting", "sha256 preferred"], "difficulty" => 1, "security" => 4, "quantum_impact" => "Grover reduces 224-bit to ~112-bit.", "post_quantum_status" => 2, "example" => ["scenario" => "Certificate fingerprint (224-bit variant)", "input" => ["cert_der" => "308202b0..." ], "output" => ["hash" => "e3b0c44298fc1c149afbf4c8996fb92427ae41e4649b934ca495991b7"]], "flow" => ["sha256 compression", "truncate to 224", "digest"], "related" => ["sha256", "sha384", "sha512"]],
        ["algo" => 41, "uuid" => "54b5a6", "name" => "sha256", "type" => "hash", "status" => "active", "title" => "SHA-256", "description_md" => "SHA-256 produces 256 bits (32 bytes) of output. Designed by NSA as part of SHA-2 family. Became the de facto cryptographic hash standard since early 2000s. Used everywhere: TLS certificates, blockchain (Bitcoin, Ethereum), code signing, password hashing (with KDFs), file integrity verification. Provides strong 256-bit security. No practical attacks. Widely available in all programming languages and cryptographic libraries. Fast performance on modern processors. Excellent cryptanalysis over 20+ years. Required knowledge for any security professional. Grover quantum attack would reduce to 128-bit security. Currently recommended for all new applications requiring a general hash function.", "mental_model" => "The gold standard vault used everywhere.", "purpose" => ["compute hash", "universal hashing"], "good_for" => ["tls", "blockchain", "file integrity", "signatures", "password kdf"], "avoid_for" => ["password hashing alone (use bcrypt/argon2)"], "pros" => ["widely supported", "fast", "256-bit security", "no attacks", "standard"], "cons" => ["password hashing needs KDF wrapper"], "difficulty" => 1, "security" => 5, "quantum_impact" => "Grover reduces 256-bit to ~128-bit.", "post_quantum_status" => 2, "example" => ["scenario" => "File integrity verification", "input" => ["file" => "release-2024.01.15.tar.gz content"], "output" => ["hash" => "8f2bc1e09c2b5e08b7f23c4e5d6a7b9d0c1e2f3a4b5c6d7e8f9a0b1c2d3e4"]], "flow" => ["padding", "512-bit blocks", "64 rounds", "256-bit digest"], "related" => ["sha224", "sha384", "sha512"]],
        ["algo" => 42, "uuid" => "fc4a02", "name" => "sha384", "type" => "hash", "status" => "active", "title" => "SHA-384", "description_md" => "SHA-384 produces 384 bits (48 bytes) of output. Part of SHA-2 family based on SHA-512 core. Uses 80 rounds with 64-bit operations. Provides 384-bit security suitable for high-security applications. Used in security-critical systems where maximum security is needed. Common in government, financial, and infrastructure cryptography. Good performance on 64-bit systems. Grover attack would reduce to 192-bit security. No practical attacks. Less widely used than SHA-256 due to larger output size. Recommended for long-term security needs (20+ years) or when policy requires 384-bit security.", "mental_model" => "Extra-secure vault for maximum security needs.", "purpose" => ["compute hash", "high-security hashing"], "good_for" => ["government systems", "long-term security", "financial cryptography"], "avoid_for" => ["none; it's secure"], "pros" => ["384-bit security", "sha2 family", "no attacks", "64-bit optimized"], "cons" => ["larger output", "slower than sha256", "rarely needed"], "difficulty" => 1, "security" => 5, "quantum_impact" => "Grover reduces 384-bit to ~192-bit.", "post_quantum_status" => 3, "example" => ["scenario" => "High-security document fingerprint", "input" => ["classified_doc" => "SECRET//NOFORN document content"], "output" => ["hash" => "a4b5c6d7e8f9a0b1c2d3e4f5a6b7c8d9e0f1a2b3c4d5e6f7a8b9c0d1e2f3a4b5c6d7e8f9a0b1c2d3"]], "flow" => ["padding", "1024-bit blocks", "80 rounds", "384-bit digest"], "related" => ["sha256", "sha512", "sha512-256"]],
        ["algo" => 43, "uuid" => "486e5b", "name" => "sha512", "type" => "hash", "status" => "active", "title" => "SHA-512", "description_md" => "SHA-512 produces 512 bits (64 bytes) of output. Core of SHA-2 family using 80 rounds with 64-bit operations. Provides 512-bit security for maximum cryptographic strength. Designed for long-term security and high-assurance applications. Used in government, military, and critical infrastructure. Excellent performance on 64-bit processors. No practical attacks in 20+ years of analysis. Grover attack would reduce to 256-bit security in quantum era. Slower than SHA-256 (larger state) but still fast. Recommended when maximum security is required (20+ year horizon). Variants like SHA-512/224 and SHA-512/256 truncate output.", "mental_model" => "Fortress-level cryptographic vault.", "purpose" => ["compute hash", "maximum security"], "good_for" => ["government", "military", "critical infrastructure", "long-term archive"], "avoid_for" => ["none; it's secure"], "pros" => ["512-bit security", "no attacks", "64-bit optimized", "strong analysis"], "cons" => ["large output", "slower than sha256"], "difficulty" => 1, "security" => 5, "quantum_impact" => "Grover reduces 512-bit to ~256-bit.", "post_quantum_status" => 3, "example" => ["scenario" => "Military-grade document signature", "input" => ["classified" => "OPSEC classified message bytes"], "output" => ["hash" => "cf83e1357eefb8bdf1542850d66d8007d620e4050b5715dc83f4a921d36ce9ce47d0d13c5d85f2b0ff8318d2877eec2f63b931bd47417a81a538327af927da3e"]], "flow" => ["padding", "1024-bit blocks", "80 rounds", "512-bit digest"], "related" => ["sha384", "sha512-224", "sha512-256"]],
        ["algo" => 44, "uuid" => "48ede7", "name" => "sha512-224", "type" => "hash", "status" => "active", "title" => "SHA-512/224", "description_md" => "SHA-512/224 is SHA-512 truncated to 224 bits (28 bytes). Uses SHA-512 compression but with different initialization and truncates output. Provides 224-bit security with 64-bit operations of SHA-512. Useful when 224-bit security is desired but 64-bit optimization is preferred. Less common than SHA-256 but available in modern libraries. Good for systems preferring SHA-512 family with smaller output. No practical attacks. Security is well-analyzed through SHA-512 analysis. Grover attack would reduce to 112-bit security. Niche use case; most applications choose SHA-256 or SHA-512 directly.", "mental_model" => "Fortress vault trimmed to 224-bit size.", "purpose" => ["compute hash", "224-bit sha512"], "good_for" => ["sha512 family compatibility", "64-bit optimization"], "avoid_for" => ["none; it's secure"], "pros" => ["224-bit output", "sha512 compression", "64-bit ops"], "cons" => ["rarely used", "sha256 usually preferred"], "difficulty" => 1, "security" => 4, "quantum_impact" => "Grover reduces 224-bit to ~112-bit.", "post_quantum_status" => 2, "example" => ["scenario" => "SHA-512 family with 224-bit output", "input" => ["data" => "truncated sha512 example"], "output" => ["hash" => "6ed0dd02806fa89e25de060c19d3ac86912f79a105f172e65466f6152ba5bc5e"]], "flow" => ["sha512 compression", "truncate to 224", "digest"], "related" => ["sha512", "sha512-256", "sha224"]],
        ["algo" => 45, "uuid" => "e7ca47", "name" => "sha512-256", "type" => "hash", "status" => "active", "title" => "SHA-512/256", "description_md" => "SHA-512/256 is SHA-512 truncated to 256 bits (32 bytes). Uses SHA-512 compression (80 rounds, 64-bit ops) with truncated output. Provides 256-bit security with larger internal state than SHA-256. Preferred by some for systems using SHA-512 infrastructure. Performance comparable to SHA-256 but uses 64-bit operations. Less common than SHA-256 but emerging in systems requiring SHA-512 family compatibility. Good cryptanalysis through SHA-512 analysis. Grover attack would reduce to 128-bit security. Suitable for general hashing in SHA-512-based systems. Most applications simply use SHA-256.", "mental_model" => "SHA-256 output through 64-bit SHA-512 machinery.", "purpose" => ["compute hash", "sha512-256 compatibility"], "good_for" => ["sha512 family systems", "64-bit optimization"], "avoid_for" => ["none; it's secure"], "pros" => ["256-bit output", "sha512 compression", "64-bit ops"], "cons" => ["less common than sha256", "rarely needed"], "difficulty" => 1, "security" => 5, "quantum_impact" => "Grover reduces 256-bit to ~128-bit.", "post_quantum_status" => 2, "example" => ["scenario" => "SHA-512 family 256-bit hash", "input" => ["message" => "sha512-256 example message"], "output" => ["hash" => "39a870a194a775fe8e0b9c90ee4f7000903a35162ba9e9e93e56ffe07a9a8dce"]], "flow" => ["sha512 compression", "truncate to 256", "digest"], "related" => ["sha512", "sha256", "sha512-224"]],
        ["algo" => 46, "uuid" => "5ca558", "name" => "sha3-224", "type" => "hash", "status" => "active", "title" => "SHA3-224", "description_md" => "SHA3-224 is the 224-bit member of SHA-3 family. Uses Keccak sponge construction with 224-bit output. Designed by Guido Bertoni et al., selected as SHA-3 standard in 2012. Provides 224-bit security with sponge's unique properties: variable output, ability to absorb/squeeze. Different from truncating SHA-512; uses different rate. Excellent cryptanalysis over 10+ years since standardization. No practical attacks. Good performance. Less commonly used than SHA3-256 due to smaller output. Suitable for 224-bit security needs using SHA-3 infrastructure. Grover attack would reduce to 112-bit security.", "mental_model" => "Sponge-based 224-bit security vault.", "purpose" => ["compute hash", "sha3 224-bit"], "good_for" => ["sha3 systems", "224-bit security"], "avoid_for" => ["none; it's secure"], "pros" => ["sponge design", "sha3 standard", "224-bit", "no attacks"], "cons" => ["sha256 usually preferred", "less deployed"], "difficulty" => 1, "security" => 4, "quantum_impact" => "Grover reduces 224-bit to ~112-bit.", "post_quantum_status" => 3, "example" => ["scenario" => "SHA-3 224-bit hash", "input" => ["message" => "sha3-224 sponge hash"], "output" => ["hash" => "e0f59c5c8bfd42e99cb32c6ee4f0a5add95e50c52f8c2661c7de5b1d"]], "flow" => ["keccak sponge", "absorb", "squeeze 224", "digest"], "related" => ["sha3-256", "sha3-384", "sha3-512"]],
        ["algo" => 47, "uuid" => "ca2db0", "name" => "sha3-256", "type" => "hash", "status" => "active", "title" => "SHA3-256", "description_md" => "SHA3-256 is the main 256-bit member of SHA-3 family. Uses Keccak sponge construction producing 256 bits (32 bytes). Selected as SHA-3 standard by NIST in 2012 after competition. Different sponge rate than truncating SHA-512. Excellent security analysis over 10+ years. No practical attacks. Good performance. Becoming more popular as SHA-3 adoption increases. Provides similar output size to SHA-256 but with different mathematical foundation. Modern choice for hash-only systems. Grover attack would reduce 256-bit to 128-bit in quantum era. Recommended for new applications choosing between SHA-256 and SHA3-256.", "mental_model" => "Sponge-based replacement for SHA-256.", "purpose" => ["compute hash", "sha3 hashing"], "good_for" => ["modern applications", "post-sha2 transition"], "avoid_for" => ["none; it's secure"], "pros" => ["sha3 standard", "sponge design", "256-bit", "no attacks"], "cons" => ["less deployed than sha256", "slightly slower"], "difficulty" => 1, "security" => 5, "quantum_impact" => "Grover reduces 256-bit to ~128-bit.", "post_quantum_status" => 3, "example" => ["scenario" => "SHA-3 cryptographic hash", "input" => ["document" => "Important document for sha3 hashing"], "output" => ["hash" => "3a985da74fe225b2045c172d6bd390bd855f086e3e9d525b46bfe24511431532"]], "flow" => ["keccak sponge", "absorb", "squeeze 256", "digest"], "related" => ["sha3-224", "sha3-384", "sha3-512"]],
        ["algo" => 48, "uuid" => "811a9d", "name" => "sha3-384", "type" => "hash", "status" => "active", "title" => "SHA3-384", "description_md" => "SHA3-384 is the 384-bit member of SHA-3 family. Uses Keccak sponge producing 384 bits (48 bytes). Part of NIST's SHA-3 standard selection (2012). Provides 384-bit security using sponge construction. Different from truncating SHA-512; uses appropriate rate parameter. Excellent long-term security properties. Good for high-security applications. Less deployed than SHA3-256 but suitable when 384-bit security needed using SHA-3. No practical attacks. Grover attack would reduce to 192-bit security. Recommended for security-critical systems transitioning to SHA-3.", "mental_model" => "High-security sponge vault.", "purpose" => ["compute hash", "high-security sha3"], "good_for" => ["government systems", "long-term security"], "avoid_for" => ["none; it's secure"], "pros" => ["sha3 standard", "384-bit", "sponge design", "no attacks"], "cons" => ["rarely used", "sha384 often preferred"], "difficulty" => 1, "security" => 5, "quantum_impact" => "Grover reduces 384-bit to ~192-bit.", "post_quantum_status" => 3, "example" => ["scenario" => "SHA-3 384-bit hash", "input" => ["secure_message" => "High-security cryptographic message"], "output" => ["hash" => "f73e191e6d76d92e0c5bff5edffe9e0c65c36f5c6c9c5b3c5a5b5c5d5e5f5a5b5c5d5e5f5a5b5c5d5e5f5a5b5c5d5e"]], "flow" => ["keccak sponge", "absorb", "squeeze 384", "digest"], "related" => ["sha3-256", "sha3-512"]],
        ["algo" => 49, "uuid" => "5783db", "name" => "sha3-512", "type" => "hash", "status" => "active", "title" => "SHA3-512", "description_md" => "SHA3-512 is the maximum 512-bit member of SHA-3 family. Uses Keccak sponge producing 512 bits (64 bytes). Part of NIST's SHA-3 standard selection (2012). Provides maximum cryptographic security (512 bits) using sponge construction. Excellent for highest-security applications. Good performance on modern systems. Less deployed than SHA3-256 due to larger output. Used in security-critical infrastructure. No practical attacks. Grover attack would reduce to 256-bit security in quantum era. Recommended for maximum-security requirements using SHA-3.", "mental_model" => "Maximum-security sponge vault.", "purpose" => ["compute hash", "maximum-security"], "good_for" => ["critical infrastructure", "maximum security"], "avoid_for" => ["none; it's secure"], "pros" => ["512-bit", "sha3 standard", "sponge design", "no attacks"], "cons" => ["large output", "rarely needed"], "difficulty" => 1, "security" => 5, "quantum_impact" => "Grover reduces 512-bit to ~256-bit.", "post_quantum_status" => 3, "example" => ["scenario" => "Maximum-security SHA-3 hash", "input" => ["critical_data" => "Critical infrastructure authentication data"], "output" => ["hash" => "afebee8b4c5f0c7f3c1c5b3c5f1c7f3c5b3c5f1c7f3c5b3c5f1c7f3c5b3c5f1c7f3c5b3c5f1c7f3c5b3c5f1c7f3c5b3c5f1c7f3c5b"]], "flow" => ["keccak sponge", "absorb", "squeeze 512", "digest"], "related" => ["sha3-256", "sha3-384"]],
        ["algo" => 50, "uuid" => "75ad1a", "name" => "keccak256", "type" => "xof", "status" => "active", "title" => "Keccak-256", "description_md" => "Keccak-256 is the raw Keccak sponge (before SHA-3 finalization) producing 256 bits. Used extensively in Ethereum and other blockchains instead of SHA3-256. Keccak and SHA-3 differ: Keccak uses different padding rules and parameters than final SHA-3 standard. Ethereum chose original Keccak-256 for compatibility reasons, not SHA3-256. This creates confusion: Ethereum documentation often says SHA-3 but means Keccak. Used for Ethereum address generation, contract hashing. Important for blockchain developers. Grover attack would reduce 256-bit to 128-bit. Different from SHA3-256; verify which one required in your system.", "mental_model" => "Original Keccak before standardization, used by Ethereum.", "purpose" => ["compute hash", "ethereum compatibility"], "good_for" => ["ethereum", "blockchain", "smart contracts"], "avoid_for" => ["if sha3 standard required"], "pros" => ["ethereum standard", "fast", "256-bit"], "cons" => ["different from sha3-256", "confusion risk"], "difficulty" => 1, "security" => 5, "quantum_impact" => "Grover reduces 256-bit to ~128-bit.", "post_quantum_status" => 3, "example" => ["scenario" => "Ethereum address generation", "input" => ["pubkey" => "0x04a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6e7f8a9b0c1d2e3f4a5b6c7d8e9f0"], "output" => ["eth_address" => "5aAeb6053ba3EFFFFFFFFFFFFFFFFFFFFFFFFFFF"]], "flow" => ["keccak absorb", "squeeze 256", "take last 160"], "related" => ["sha3-256", "ethereum", "keccak512"]],
        ["algo" => 51, "uuid" => "c71bf9", "name" => "keccak512", "type" => "xof", "status" => "active", "title" => "Keccak-512", "description_md" => "Keccak-512 is the raw Keccak sponge (before SHA-3 standardization) producing 512 bits. Similar relationship to Keccak-256: original Keccak before SHA-3 finalization. Less commonly used than Keccak-256. Some blockchains and specialized applications use it. Provides 512-bit security with Keccak sponge. Good for high-security requirements with Keccak architecture. Different from SHA3-512 like Keccak-256 differs from SHA3-256. Grover attack would reduce 512-bit to 256-bit. Used primarily in legacy systems choosing original Keccak over final SHA-3.", "mental_model" => "Original Keccak at 512-bit scale.", "purpose" => ["compute hash", "high-security keccak"], "good_for" => ["legacy keccak systems", "high-security needs"], "avoid_for" => ["sha3 standard required"], "pros" => ["512-bit", "keccak sponge", "fast"], "cons" => ["rarely used", "different from sha3"], "difficulty" => 1, "security" => 5, "quantum_impact" => "Grover reduces 512-bit to ~256-bit.", "post_quantum_status" => 3, "example" => ["scenario" => "High-security Keccak hash", "input" => ["data" => "High security keccak512 example"], "output" => ["hash" => "a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6e7f8a9b0c1d2e3f4a5b6c7d8e9f0a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6e7f8a9b0c1d2e3f4"]], "flow" => ["keccak absorb", "squeeze 512", "digest"], "related" => ["keccak256", "sha3-512"]],
        ["algo" => 52, "uuid" => "820fde", "name" => "shake128", "type" => "xof", "status" => "active", "title" => "SHAKE128", "description_md" => "SHAKE128 is an eXtendable Output Function (XOF) from SHA-3 standard. Allows arbitrary output length (any number of bytes). Uses Keccak sponge with rate optimized for 128-bit security level. Absorb input, squeeze arbitrary output. Useful for variable-length hash outputs, key derivation functions, random number generation. No practical attacks. Excellent cryptanalysis. Grover attack would reduce 128-bit to 64-bit. Used in post-quantum cryptography and modern KDFs. More flexible than fixed-size hashes. Performance is excellent.", "mental_model" => "Extendable sponge producing 128-bit security.", "purpose" => ["xof", "variable hash", "kdf", "rng"], "good_for" => ["key derivation", "variable output", "post-quantum prep"], "avoid_for" => ["fixed-size hash needs"], "pros" => ["variable output", "xof design", "128-bit security", "standard"], "cons" => ["slower per byte than fixed", "requires output length spec"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Grover reduces to ~64-bit at 128-bit security.", "post_quantum_status" => 3, "example" => ["scenario" => "KDF with variable output length", "input" => ["seed" => "a1b2c3d4e5f6a7b8", "output_length" => 32], "output" => ["hash_32" => "c5d6e7f8a9b0c1d2e3f4a5b6c7d8e9f0a1b2c3d4e5f6a7b8c9d0e1f2a3b4"]], "flow" => ["absorb seed", "squeeze 32 bytes", "variable output"], "related" => ["shake256", "blake3", "argon2"]],
        ["algo" => 53, "uuid" => "bcc1da", "name" => "shake256", "type" => "xof", "status" => "active", "title" => "SHAKE256", "description_md" => "SHAKE256 is an eXtendable Output Function (XOF) from SHA-3 standard. Produces arbitrary output length with 256-bit security level. Uses Keccak sponge with appropriate rate. Used for variable-length keys, post-quantum cryptography, general KDFs. Excellent cryptanalysis. No practical attacks. More security than SHAKE128, useful for long-term security. Grover attack would reduce 256-bit to 128-bit. NIST recommends SHAKE256 for post-quantum applications. Good performance. Provides flexibility of variable output with strong security.", "mental_model" => "Extendable sponge producing 256-bit security.", "purpose" => ["xof", "variable hash", "post-quantum kdf"], "good_for" => ["post-quantum crypto", "key derivation", "variable output"], "avoid_for" => ["fixed-size hash needs"], "pros" => ["256-bit security", "xof design", "post-quantum safe", "variable"], "cons" => ["requires output length", "slower per byte"], "difficulty" => 2, "security" => 5, "quantum_impact" => "Grover reduces 256-bit to ~128-bit.", "post_quantum_status" => 4, "example" => ["scenario" => "Post-quantum key derivation", "input" => ["entropy" => "fresh_quantum_random_256bit", "output_length" => 64], "output" => ["derived_key" => "d1e2f3a4b5c6d7e8f9a0b1c2d3e4f5a6b7c8d9e0f1a2b3c4d5e6f7a8b9c0d1e2f3a4b5c6d7e8f9a0b1c2d3e4f5a6b7c8d9"]], "flow" => ["absorb entropy", "squeeze 64", "post-quantum secure"], "related" => ["shake128", "blake3"]],
        ["algo" => 54, "uuid" => "2cf788", "name" => "cshake128", "type" => "xof", "status" => "active", "title" => "cSHAKE128", "description_md" => "cSHAKE128 is customizable SHAKE128 from SHA-3 standard. Allows domain separation via custom string parameter, preventing domain confusion attacks. Uses Keccak sponge with custom domain prefix. Useful for multiple hash functions deriving from same sponge. Prevents attacks where malicious input could confuse two independent uses. Good for protocol design requiring domain-separated hashes. 128-bit security level. Excellent analysis. No practical attacks. Grover would reduce to 64-bit. Used in modern cryptographic protocols.", "mental_model" => "Customizable sponge with domain labels.", "purpose" => ["xof", "domain-separated hash"], "good_for" => ["protocol design", "domain separation"], "avoid_for" => ["simple hashing"], "pros" => ["domain separation", "xof", "128-bit", "standard"], "cons" => ["requires domain parameter", "more complex"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Grover reduces to ~64-bit.", "post_quantum_status" => 3, "example" => ["scenario" => "Domain-separated KDF", "input" => ["input" => "secret_material", "custom" => "app_v1_key", "output_length" => 32], "output" => ["key" => "e5f6a7b8c9d0e1f2a3b4c5d6e7f8a9b0c1d2e3f4a5b6c7d8e9f0a1b2c3d4"]], "flow" => ["custom domain prefix", "absorb", "squeeze 32", "separated"], "related" => ["cshake256", "shake128"]],
        ["algo" => 55, "uuid" => "fe6aaf", "name" => "cshake256", "type" => "xof", "status" => "active", "title" => "cSHAKE256", "description_md" => "cSHAKE256 is customizable SHAKE256 from SHA-3 standard with 256-bit security. Domain separation via custom string parameter. Prevents confusion attacks in protocol design. Uses Keccak sponge with domain prefix. Excellent for cryptographic protocols requiring multiple derived functions. 256-bit security. No practical attacks. Grover would reduce to 128-bit. NIST recommends for protocol-level domain separation. Good performance. Becoming more common in modern protocol standards.", "mental_model" => "256-bit customizable sponge with domain labels.", "purpose" => ["xof", "post-quantum domain separation"], "good_for" => ["protocol design", "post-quantum separation"], "avoid_for" => ["simple hashing"], "pros" => ["256-bit security", "domain separation", "post-quantum"], "cons" => ["requires domain string", "complex"], "difficulty" => 2, "security" => 5, "quantum_impact" => "Grover reduces 256-bit to ~128-bit.", "post_quantum_status" => 4, "example" => ["scenario" => "Post-quantum protocol domain separation", "input" => ["material" => "pqc_key_material", "domain" => "kyber512_session", "output_length" => 64], "output" => ["separated_key" => "f7a8b9c0d1e2f3a4b5c6d7e8f9a0b1c2d3e4f5a6b7c8d9e0f1a2b3c4d5e6f7a8b9c0d1e2f3a4b5c6d7e8f9a0b1c2d3e4f5a6b7c8"]], "flow" => ["domain prefix", "absorb", "squeeze 64", "pqc safe"], "related" => ["cshake128", "shake256"]],
        ["algo" => 56, "uuid" => "65ad28", "name" => "kmac128", "type" => "xof", "status" => "active", "title" => "KMAC128", "description_md" => "KMAC128 (Keccak Message Authentication Code) is a MAC function from SHA-3 standard. Uses SHAKE128 XOF with key and message. Produces authentication code with 128-bit security. NIST approved for authenticated hashing. Different from HMAC: uses sponge directly. Authenticated encryption applications. Can produce arbitrary output length. No practical attacks. Grover would reduce to 64-bit. Good for modern authenticated hashing. Used when both hash and authentication needed.", "mental_model" => "Keyed sponge authentication with 128-bit security.", "purpose" => ["mac", "authenticated hash"], "good_for" => ["message authentication", "authenticated encryption"], "avoid_for" => ["simple hashing"], "pros" => ["128-bit security", "nist approved", "variable output"], "cons" => ["requires key", "requires output length"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Grover reduces to ~64-bit.", "post_quantum_status" => 3, "example" => ["scenario" => "Message authentication code", "input" => ["key" => "a1b2c3d4e5f6a7b8", "message" => "authenticated message data", "output_length" => 32], "output" => ["mac" => "d5e6f7a8b9c0d1e2f3a4b5c6d7e8f9a0b1c2d3e4f5a6b7c8d9e0f1a2b3c4"]], "flow" => ["absorb key", "absorb message", "squeeze 32", "mac"], "related" => ["kmac256", "hmac"]],
        ["algo" => 57, "uuid" => "976b1b", "name" => "kmac256", "type" => "xof", "status" => "active", "title" => "KMAC256", "description_md" => "KMAC256 is the 256-bit version of KMAC with 256-bit security level. Uses SHAKE256 XOF with key and message. NIST-approved MAC function. Produces variable-length authentication codes. Stronger security than KMAC128. Used for high-security authenticated hashing. No practical attacks. Grover would reduce to 128-bit. Good for post-quantum preparation. Recommended for new authenticated hash designs.", "mental_model" => "256-bit keyed sponge authentication.", "purpose" => ["mac", "authenticated hash"], "good_for" => ["secure authentication", "post-quantum prep"], "avoid_for" => ["simple hashing"], "pros" => ["256-bit security", "nist approved", "variable output"], "cons" => ["requires key", "output length needed"], "difficulty" => 2, "security" => 5, "quantum_impact" => "Grover reduces 256-bit to ~128-bit.", "post_quantum_status" => 4, "example" => ["scenario" => "High-security message authentication", "input" => ["key" => "0x" . bin2hex(random_bytes(32)), "message" => "secure authenticated data", "output_length" => 64], "output" => ["mac" => "e0f1a2b3c4d5e6f7a8b9c0d1e2f3a4b5c6d7e8f9a0b1c2d3e4f5a6b7c8d9e0f1a2b3c4d5e6f7a8b9c0d1e2f3a4b5c6d7e8f9a0"]], "flow" => ["absorb key", "absorb message", "squeeze 64", "high security"], "related" => ["kmac128", "hmac"]],
        ["algo" => 58, "uuid" => "533af4", "name" => "kmacxof128", "type" => "xof", "status" => "active", "title" => "KMACxof128", "description_md" => "KMACxof128 is KMAC128 in XOF mode from SHA-3 standard. Uses SHAKE128 as underlying XOF. Produces variable-length output authenticated by key. Differs from KMAC: this is pure XOF without length prefix. 128-bit security. NIST approved. Used for key derivation with authentication. Good for generating multiple keys from single material. No practical attacks. Grover reduces to 64-bit. Used in modern key derivation protocols.", "mental_model" => "Keyed 128-bit XOF for variable authentication.", "purpose" => ["xof", "authenticated key derivation"], "good_for" => ["multi-key derivation", "authenticated kdf"], "avoid_for" => ["simple hashing"], "pros" => ["128-bit", "xof mode", "authenticated"], "cons" => ["requires key", "xof specific"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Grover reduces to ~64-bit.", "post_quantum_status" => 3, "example" => ["scenario" => "Authenticated key generation", "input" => ["key" => "master_secret_key", "output_length" => 96], "output" => ["three_keys" => "a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6e7f8a9b0c1d2e3f4a5b6c7d8e9f0a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6e7f8a9b0c1d2"]], "flow" => ["absorb key", "squeeze 96", "split for 3 keys"], "related" => ["kmacxof256", "shake128"]],
        ["algo" => 59, "uuid" => "d8709c", "name" => "kmacxof256", "type" => "xof", "status" => "active", "title" => "KMACxof256", "description_md" => "KMACxof256 is KMAC256 in XOF mode with 256-bit security. Uses SHAKE256 as underlying XOF. Variable-length authenticated output. NIST approved for key derivation. Stronger than KMACxof128. Used for secure multi-key generation. No practical attacks. Grover reduces to 128-bit. Recommended for post-quantum key derivation. Good performance.", "mental_model" => "Keyed 256-bit XOF for authenticated keys.", "purpose" => ["xof", "post-quantum key derivation"], "good_for" => ["secure key generation", "post-quantum kdf"], "avoid_for" => ["simple hashing"], "pros" => ["256-bit", "xof", "post-quantum", "nist"], "cons" => ["requires key", "xof mode"], "difficulty" => 2, "security" => 5, "quantum_impact" => "Grover reduces 256-bit to ~128-bit.", "post_quantum_status" => 4, "example" => ["scenario" => "Post-quantum key derivation", "input" => ["secret" => "quantum_resistant_seed", "output_length" => 128], "output" => ["keys" => "f0a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6e7f8a9b0c1d2e3f4a5b6c7d8e9f0a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6e7f8a9b0c1d2e3f4"]], "flow" => ["absorb secret", "squeeze 128", "pqc safe"], "related" => ["kmacxof128", "shake256"]],
        ["algo" => 60, "uuid" => "480a4f", "name" => "parallelhash128", "type" => "xof", "status" => "active", "title" => "ParallelHash128", "description_md" => "ParallelHash128 is a parallelizable hash from SHA-3 standard with 128-bit security. Uses SHAKE128 in tree mode for parallel processing. Absorbs data in parallel chunks, combines results. Useful for hashing very large files on multi-core systems. 128-bit security level. No practical attacks. Grover reduces to 64-bit. Good performance on many-core architectures. Less common than sequential hashing. Used in systems with large datasets and parallel processing capability.", "mental_model" => "128-bit parallel tree hash for multi-core.", "purpose" => ["parallel hash", "large data"], "good_for" => ["parallel processing", "large files"], "avoid_for" => ["sequential systems"], "pros" => ["128-bit", "parallel friendly", "tree structure"], "cons" => ["requires chunking", "parallel complexity"], "difficulty" => 3, "security" => 4, "quantum_impact" => "Grover reduces to ~64-bit.", "post_quantum_status" => 3, "example" => ["scenario" => "Parallel hashing of 4GB file", "input" => ["file_chunk1" => "first 1gb chunk", "file_chunk2" => "second 1gb chunk", "file_chunk3" => "third 1gb chunk", "file_chunk4" => "fourth 1gb chunk"], "output" => ["parallel_hash" => "a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6"]], "flow" => ["parallel chunks", "merge tree", "128-bit digest"], "related" => ["parallelhash256", "blake3"]],
        ["algo" => 61, "uuid" => "8f1770", "name" => "parallelhash256", "type" => "xof", "status" => "active", "title" => "ParallelHash256", "description_md" => "ParallelHash256 is the 256-bit version of ParallelHash with enhanced security. Uses SHAKE256 in tree mode. Processes large data in parallel chunks on multi-core systems. 256-bit security. No practical attacks. Grover reduces to 128-bit. Good for high-security parallel hashing. Less common but suitable for critical systems processing large datasets. Tree structure prevents some attacks.", "mental_model" => "256-bit parallel tree hash.", "purpose" => ["parallel hash", "large high-security data"], "good_for" => ["secure parallel processing", "critical large data"], "avoid_for" => ["sequential systems"], "pros" => ["256-bit", "parallel", "tree secure"], "cons" => ["complex", "multi-core needed"], "difficulty" => 3, "security" => 5, "quantum_impact" => "Grover reduces 256-bit to ~128-bit.", "post_quantum_status" => 4, "example" => ["scenario" => "Secure parallel archive hash", "input" => ["chunk1" => "archive_part_1", "chunk2" => "archive_part_2", "chunk3" => "archive_part_3"], "output" => ["archive_hash" => "c5d6e7f8a9b0c1d2e3f4a5b6c7d8e9f0a1b2c3d4e5f6a7b8c9d0e1f2a3b4"]], "flow" => ["parallel chunks", "tree merge", "256-bit digest"], "related" => ["parallelhash128", "blake3"]],
        ["algo" => 62, "uuid" => "03b466", "name" => "tuplehash128", "type" => "xof", "status" => "active", "title" => "TupleHash128", "description_md" => "TupleHash128 is a tuple-aware hash from SHA-3 standard. Hashes variable-length sequences (tuples) with proper domain separation between elements. 128-bit security. Prevents domain confusion when hashing multiple inputs. Each element properly separated. NIST approved for structured data. No practical attacks. Grover reduces to 64-bit. Used when hashing multiple distinct values that must be separated.", "mental_model" => "128-bit tuple separator for structured hashing.", "purpose" => ["structured hash", "tuple hashing"], "good_for" => ["multi-element hashing", "structured data"], "avoid_for" => ["simple hashing"], "pros" => ["128-bit", "tuple safe", "domain separated"], "cons" => ["requires tuple structure"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Grover reduces to ~64-bit.", "post_quantum_status" => 3, "example" => ["scenario" => "Hash multiple values safely", "input" => ["name" => "Alice", "email" => "alice@example.com", "id" => "12345"], "output" => ["tuple_hash" => "f1a2b3c4d5e6f7a8b9c0d1e2f3a4b5c6"]], "flow" => ["hash name", "hash email", "hash id", "combine", "128-bit"], "related" => ["tuplehash256", "cshake128"]],
        ["algo" => 63, "uuid" => "45c9fb", "name" => "tuplehash256", "type" => "xof", "status" => "active", "title" => "TupleHash256", "description_md" => "TupleHash256 is the 256-bit version with domain-separated tuple hashing. Hashes variable-length sequences (tuples) safely. Prevents confusion between elements. 256-bit security. NIST approved. Good for structured cryptographic data. No practical attacks. Grover reduces to 128-bit. Recommended for protocol hashing of multiple distinct values.", "mental_model" => "256-bit tuple separator for structured data.", "purpose" => ["structured hash", "post-quantum tuple"], "good_for" => ["protocol tuples", "multi-element security"], "avoid_for" => ["simple hashing"], "pros" => ["256-bit", "tuple safe", "post-quantum"], "cons" => ["requires tuple structure"], "difficulty" => 2, "security" => 5, "quantum_impact" => "Grover reduces 256-bit to ~128-bit.", "post_quantum_status" => 4, "example" => ["scenario" => "Protocol tuple hashing", "input" => ["version" => "1", "session_id" => "0xa1b2c3d4", "timestamp" => "1673829600"], "output" => ["tuple_hash" => "d1e2f3a4b5c6d7e8f9a0b1c2d3e4f5a6b7c8d9e0f1a2b3c4d5e6f7a8b9"]], "flow" => ["separate version", "separate session", "separate timestamp", "256-bit"], "related" => ["tuplehash128"]],
        ["algo" => 64, "uuid" => "0dc28b", "name" => "kangarootwelve", "type" => "xof", "status" => "active", "title" => "KangarooTwelve", "description_md" => "KangarooTwelve is an extremely fast XOF designed by Guido Bertoni et al. Uses Keccak-p permutation (same as Keccak) but with lightweight structuring. Parallel tree hashing at algorithm level. Produces arbitrary output. Designed for high-speed applications. No practical attacks. Excellent performance. Less standard than SHAKE but excellent design. Used in systems prioritizing speed with Keccak foundation. Good for streaming and large data.", "mental_model" => "Speedy parallel kangaroo hash.", "purpose" => ["xof", "fast parallel hash"], "good_for" => ["high-speed hashing", "large data streaming"], "avoid_for" => ["standard compliance required"], "pros" => ["very fast", "parallel friendly", "arbitrary output"], "cons" => ["less standardized", "niche use"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Grover reduces by sqrt.", "post_quantum_status" => 3, "example" => ["scenario" => "Fast parallel hash", "input" => ["data" => "large_stream_data_chunk"], "output" => ["hash" => "a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6e7f8a9b0c1d2e3f4a5b6c7d8e9f0"]], "flow" => ["parallel tree", "keccak-p", "squeeze arbitrary"], "related" => ["marsupilami14", "blake3"]],
        ["algo" => 65, "uuid" => "0bf8aa", "name" => "marsupilami14", "type" => "xof", "status" => "active", "title" => "Marsupilami14", "description_md" => "Marsupilami14 is the predecessor/variant of KangarooTwelve. Uses Keccak-p with different structuring. Parallel tree XOF. Slightly different from KangarooTwelve but same design philosophy. Very fast with arbitrary output. Good cryptanalysis. No practical attacks. Less common than KangarooTwelve. Used in niche systems. Same security foundations as KangarooTwelve.", "mental_model" => "Earlier kangaroo parallel hash design.", "purpose" => ["xof", "parallel fast hash"], "good_for" => ["legacy keccak systems", "fast hashing"], "avoid_for" => ["new applications"], "pros" => ["fast", "parallel", "arbitrary output"], "cons" => ["less standardized", "kangarootwelve preferred"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Grover reduces by sqrt.", "post_quantum_status" => 3, "example" => ["scenario" => "Fast parallel hashing", "input" => ["stream" => "data_stream_chunk"], "output" => ["hash" => "b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6e7f8a9b0c1d2e3f4a5b6c7d8e9f0a1"]], "flow" => ["parallel tree", "keccak-p", "marsupilami structuring"], "related" => ["kangarootwelve"]],
        ["algo" => 66, "uuid" => "8e41ee", "name" => "blake2b", "type" => "hash", "status" => "active", "title" => "BLAKE2b", "description_md" => "BLAKE2b is a modern cryptographic hash producing 512 bits (64 bytes). Optimized for 64-bit processors. Based on BLAKE (SHA-3 finalist). Much faster than MD5, SHA-1, SHA-2 while being more secure. Uses ChaCha permutation. Supports tree hashing and personalization. No practical attacks. Excellent analysis. Used in systems prioritizing speed and security. Popular choice for modern applications. Grover reduces to 256-bit security. Recommended for general-purpose hashing when speed matters.", "mental_model" => "Speedy 512-bit vault with no known vulnerabilities.", "purpose" => ["compute hash", "fast secure hashing"], "good_for" => ["general hashing", "speed critical", "tree mode"], "avoid_for" => ["none; it's excellent"], "pros" => ["very fast", "no attacks", "512-bit", "tree mode", "personalization"], "cons" => ["less standardized than sha2"], "difficulty" => 1, "security" => 5, "quantum_impact" => "Grover reduces 512-bit to ~256-bit.", "post_quantum_status" => 3, "example" => ["scenario" => "Fast cryptographic hash", "input" => ["data" => "blake2b_test_message_data"], "output" => ["hash" => "ca002330e69d3e6b84a546f5fe1d3b91f4c3a061c899405efd0a847e933bf61cf8798b38df01ef9fbea52d0f1e765b11"]], "flow" => ["padding", "12 rounds", "512-bit digest"], "related" => ["blake2s", "blake3", "sha512"]],
        ["algo" => 67, "uuid" => "79647a", "name" => "blake2s", "type" => "hash", "status" => "active", "title" => "BLAKE2s", "description_md" => "BLAKE2s is BLAKE2b for 32-bit systems, producing 256 bits (32 bytes). Optimized for 32-bit processors and embedded systems. Fast on ARMs and microcontrollers. Same security foundations as BLAKE2b at 256-bit level. Excellent analysis. No practical attacks. Good for embedded and IoT applications. Grover reduces to 128-bit security. Used in systems with 32-bit processors or 256-bit output needs. Popular in cryptographic libraries.", "mental_model" => "Speedy 256-bit hash for 32-bit systems.", "purpose" => ["compute hash", "embedded hashing"], "good_for" => ["32-bit systems", "embedded crypto", "iot"], "avoid_for" => ["none; it's solid"], "pros" => ["32-bit optimized", "256-bit", "fast", "no attacks"], "cons" => ["less standardized"], "difficulty" => 1, "security" => 5, "quantum_impact" => "Grover reduces 256-bit to ~128-bit.", "post_quantum_status" => 3, "example" => ["scenario" => "Embedded device hash", "input" => ["device_data" => "sensor_readings_and_timestamp"], "output" => ["hash" => "d7a8fbb307d7809469ca9abdcbed1b8215f9e6d124cc91fd931d75ae40cdc1412"]], "flow" => ["padding", "10 rounds 32-bit", "256-bit digest"], "related" => ["blake2b", "blake3"]],
        ["algo" => 68, "uuid" => "a3c13a", "name" => "blake2bp", "type" => "hash", "status" => "active", "title" => "BLAKE2bp", "description_md" => "BLAKE2bp is parallelized BLAKE2b for multi-core systems. Hashes data in parallel chunks (4 threads by default). Combines chunks at end. Fast on multi-core CPUs. 512-bit output. No practical attacks. Good for very large files. Grover reduces to 256-bit security. Used in systems with many cores. Similar security to BLAKE2b but faster on parallel systems.", "mental_model" => "Parallel 512-bit BLAKE2 for multi-core.", "purpose" => ["parallel hash", "large files"], "good_for" => ["multi-core systems", "large data"], "avoid_for" => ["sequential systems"], "pros" => ["parallel fast", "512-bit", "no attacks"], "cons" => ["requires multiple cores"], "difficulty" => 2, "security" => 5, "quantum_impact" => "Grover reduces 512-bit to ~256-bit.", "post_quantum_status" => 3, "example" => ["scenario" => "Parallel 4GB file hash", "input" => ["chunk1" => "1gb_part_1", "chunk2" => "1gb_part_2", "chunk3" => "1gb_part_3", "chunk4" => "1gb_part_4"], "output" => ["parallel_hash" => "af1678f5d4f1e6a3b2c7d8e9f0a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6e7f8a9b0c1d2e3f4a5b6c7d8e9f0a1b2c3d4e5f6"]], "flow" => ["parallel blake2b", "chunk merge", "512-bit digest"], "related" => ["blake2b", "blake2sp"]],
        ["algo" => 69, "uuid" => "815766", "name" => "blake2sp", "type" => "hash", "status" => "active", "title" => "BLAKE2sp", "description_md" => "BLAKE2sp is parallelized BLAKE2s for multi-core 32-bit systems. Hashes data in parallel chunks (4 threads). Fast on ARM/embedded multi-core systems. 256-bit output. No practical attacks. Good for embedded systems with multiple cores. Grover reduces to 128-bit security. Similar security to BLAKE2s but faster in parallel. Less common than BLAKE2bp but useful for specific embedded scenarios.", "mental_model" => "Parallel 256-bit BLAKE2 for 32-bit cores.", "purpose" => ["parallel hash", "embedded multi-core"], "good_for" => ["32-bit multi-core systems", "embedded"], "avoid_for" => ["single-core systems"], "pros" => ["parallel fast", "256-bit", "32-bit optimized"], "cons" => ["needs multiple cores"], "difficulty" => 2, "security" => 5, "quantum_impact" => "Grover reduces 256-bit to ~128-bit.", "post_quantum_status" => 3, "example" => ["scenario" => "Parallel ARM hash", "input" => ["chunk_a" => "stream_chunk_a", "chunk_b" => "stream_chunk_b", "chunk_c" => "stream_chunk_c"], "output" => ["hash" => "a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6e7f8a9b0c1d2e3f4a5b6c7d8e9f0"]], "flow" => ["parallel blake2s", "merge", "256-bit"], "related" => ["blake2s", "blake2bp"]],
        ["algo" => 70, "uuid" => "e1c6d8", "name" => "blake3", "type" => "xof", "status" => "active", "title" => "BLAKE3", "description_md" => "BLAKE3 is the newest member of BLAKE family, designed by Jack O'Connor et al. (2020). XOF with variable output. Uses BLAKE2 core with merkle tree structure. Parallel hashing built into algorithm. Produces any output length. Cryptanalysis ongoing but excellent security design. No practical attacks. Extremely fast on all platforms (32/64-bit). Tree structure provides parallelism. Used in modern systems. Grover reduces security by sqrt. Recommended for new applications when BLAKE2 simplicity with XOF flexibility desired. Becoming standard in modern libraries.", "mental_model" => "Latest BLAKE generation with tree and variable output.", "purpose" => ["xof", "general hashing", "streaming"], "good_for" => ["modern applications", "streaming", "variable output"], "avoid_for" => ["none; it's excellent"], "pros" => ["xof flexible", "very fast", "parallel friendly", "tree safe", "no attacks"], "cons" => ["newest, less deployed"], "difficulty" => 1, "security" => 5, "quantum_impact" => "Grover reduces security by sqrt.", "post_quantum_status" => 4, "example" => ["scenario" => "Modern streaming hash", "input" => ["stream" => "continuous_data_stream_bytes"], "output" => ["variable_hash_32" => "d1e2f3a4b5c6d7e8f9a0b1c2d3e4f5a6b7c8d9e0f1a2b3c4d5e6f7a8b9"]], "flow" => ["blake3 tree", "parallel chunks", "variable output"], "related" => ["blake2b", "blake2s"]],
        ["algo" => 71, "uuid" => "566232", "name" => "skein256", "type" => "hash", "status" => "active", "title" => "Skein-256", "description_md" => "Skein-256 is the 256-bit member of Skein family designed by Bruce Schneier et al. (SHA-3 finalist). Uses Threefish block cipher core. Produces 256 bits (32 bytes). Did not win SHA-3 competition but excellent security. Tree hashing support. No practical attacks. Good cryptanalysis. Used in niche systems and security-conscious projects. Performance is good. Grover reduces to 128-bit security. Solid alternative to SHA-256 for systems that prefer AES-independent cryptography.", "mental_model" => "SHA-3 finalist 256-bit vault.", "purpose" => ["compute hash", "threefish based"], "good_for" => ["security conscious systems", "non-aes preference"], "avoid_for" => ["none; it's solid"], "pros" => ["256-bit", "no attacks", "tree mode", "sha3 finalist"], "cons" => ["less adopted than sha"], "difficulty" => 2, "security" => 5, "quantum_impact" => "Grover reduces 256-bit to ~128-bit.", "post_quantum_status" => 3, "example" => ["scenario" => "Threefish-based hash", "input" => ["message" => "Skein hash example"], "output" => ["hash" => "f6c2c1c4b8f4e9a3d5c7b9e1f3a5b7c9d1e3f5a7b9c1d3e5f7a9b1c3d5e7"]], "flow" => ["padding", "80 rounds threefish", "256-bit digest"], "related" => ["skein512", "skein1024"]],
        ["algo" => 72, "uuid" => "937995", "name" => "skein512", "type" => "hash", "status" => "active", "title" => "Skein-512", "description_md" => "Skein-512 is the 512-bit member producing 512 bits (64 bytes). Uses Threefish-512 block cipher. Part of Skein family (SHA-3 finalist). Tree hashing built-in. No practical attacks. Excellent security analysis. Good for high-security systems. Performance comparable to SHA-512. Grover reduces to 256-bit security. Used in privacy-focused projects and systems avoiding MD5/SHA lineage. Solid choice for maximum security with non-standard design.", "mental_model" => "SHA-3 finalist 512-bit vault.", "purpose" => ["compute hash", "high-security"], "good_for" => ["privacy systems", "non-aes design"], "avoid_for" => ["none; it's excellent"], "pros" => ["512-bit", "no attacks", "tree mode", "threefish core"], "cons" => ["less adopted"], "difficulty" => 2, "security" => 5, "quantum_impact" => "Grover reduces 512-bit to ~256-bit.", "post_quantum_status" => 3, "example" => ["scenario" => "High-security threefish hash", "input" => ["data" => "Maximum security hash example"], "output" => ["hash" => "a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6e7f8a9b0c1d2e3f4a5b6c7d8e9f0a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6e7f8a9b0c1d2e3f4"]], "flow" => ["padding", "80 rounds threefish-512", "512-bit digest"], "related" => ["skein256", "skein1024"]],
        ["algo" => 73, "uuid" => "c6c52a", "name" => "skein1024", "type" => "hash", "status" => "active", "title" => "Skein-1024", "description_md" => "Skein-1024 is the largest Skein variant producing 1024 bits (128 bytes). Uses Threefish-1024 block cipher. Maximum output in Skein family. Provides absolute maximum cryptographic security. Tree hashing support. No practical attacks. Good cryptanalysis. Rarely needed but available for absolute maximum security. Grover reduces to 512-bit security. Used in systems requiring absolute security guarantees over very long horizons.", "mental_model" => "Maximum-security threefish vault.", "purpose" => ["maximum security hash"], "good_for" => ["long-term security", "maximum assurance"], "avoid_for" => ["anything else"], "pros" => ["1024-bit", "maximum", "no attacks"], "cons" => ["rarely needed", "huge output"], "difficulty" => 2, "security" => 5, "quantum_impact" => "Grover reduces 1024-bit to ~512-bit.", "post_quantum_status" => 4, "example" => ["scenario" => "Absolute maximum security archive", "input" => ["critical_data" => "Most critical long-term archive"], "output" => ["hash" => "b1c2d3e4f5a6b7c8d9e0f1a2b3c4d5e6f7a8b9c0d1e2f3a4b5c6d7e8f9a0b1c2d3e4f5a6b7c8d9e0f1a2b3c4d5e6f7a8b9c0d1e2f3a4b5c6d7e8f9a0b1c2d3e4f5a6b7c8d9e0f1a2b3c4d5e6f7a8b9c0d1e2f3a4b5c6d7e8f9a0b1c2d3e4f5a6b7c8d9e0f1a2b3c4d5e6f7a8b9c0d1e2f3a4"]], "flow" => ["padding", "80 rounds threefish-1024", "1024-bit digest"], "related" => ["skein256", "skein512"]],
        ["algo" => 74, "uuid" => "fb259e", "name" => "sm3", "type" => "hash", "status" => "active", "title" => "SM3", "description_md" => "SM3 is the Chinese cryptographic hash standard designed by Xiaoyun Wang et al. Produces 256 bits (32 bytes). Part of SM family (Chinese state standard). Used in Chinese government, banking, and government systems. Structurally similar to SHA-2 but with different constants. Good cryptanalysis, no practical attacks. Security comparable to SHA-256. Grover reduces to 128-bit security. Required for systems operating in China or with Chinese government systems. Useful for international systems requiring Chinese standard compatibility. Otherwise, SHA-256 is preferred.", "mental_model" => "Chinese standard 256-bit hash.", "purpose" => ["compute hash", "chinese compatibility"], "good_for" => ["chinese government", "banking in china"], "avoid_for" => ["unless required"], "pros" => ["256-bit", "chinese standard", "no attacks"], "cons" => ["less international adoption"], "difficulty" => 1, "security" => 4, "quantum_impact" => "Grover reduces 256-bit to ~128-bit.", "post_quantum_status" => 2, "example" => ["scenario" => "Chinese government document hash", "input" => ["document" => "中国政府公文document"], "output" => ["hash" => "e3b0c44298fc1c149afbf4c8996fb92427ae41e4649b934ca495991b7"]], "flow" => ["padding", "64 rounds", "256-bit digest"], "related" => ["sha256", "streebog256"]],
        ["algo" => 76, "uuid" => "19a428", "name" => "streebog256", "type" => "hash", "status" => "active", "title" => "Streebog-256", "description_md" => "Streebog-256 is the Russian cryptographic hash standard (GOST R 34.11-2012) producing 256 bits (32 bytes). Replaces older GOST R 34.11-94. Uses GOST cipher core. Better security properties than predecessor. Good cryptanalysis. No practical attacks. Required for Russian government and banking systems. Grover reduces to 128-bit security. Used in Russian infrastructure and systems complying with Russian standards. Otherwise, SHA-256 is internationally preferred.", "mental_model" => "Russian standard 256-bit hash.", "purpose" => ["compute hash", "russian compatibility"], "good_for" => ["russian government", "russian banking"], "avoid_for" => ["unless required"], "pros" => ["256-bit", "russian standard", "improved security"], "cons" => ["limited international adoption"], "difficulty" => 1, "security" => 4, "quantum_impact" => "Grover reduces 256-bit to ~128-bit.", "post_quantum_status" => 2, "example" => ["scenario" => "Russian government document", "input" => ["document" => "Российское государственное письмо"], "output" => ["hash" => "af21a1b220e93b5f2b96f82dde0d9dbe9b997d8b221bd38edd9e9f81ef5ef1e0"]], "flow" => ["gost cipher", "64 rounds", "256-bit digest"], "related" => ["streebog512", "gost-r-34.11-94"]],
        ["algo" => 77, "uuid" => "4b54be", "name" => "streebog512", "type" => "hash", "status" => "active", "title" => "Streebog-512", "description_md" => "Streebog-512 is the 512-bit variant of Russian GOST R 34.11-2012 producing 512 bits (64 bytes). Uses GOST cipher core with extended state. Higher security margin than 256-bit variant. Good cryptanalysis. No practical attacks. Required for maximum-security Russian systems. Grover reduces to 256-bit security. Used in Russian high-security infrastructure. Excellent choice when 512-bit security with Russian standard required.", "mental_model" => "Russian standard 512-bit hash.", "purpose" => ["high-security hash", "russian max security"], "good_for" => ["russian high-security", "long-term russian"], "avoid_for" => ["unless required"], "pros" => ["512-bit", "russian standard", "strong"], "cons" => ["limited adoption"], "difficulty" => 1, "security" => 5, "quantum_impact" => "Grover reduces 512-bit to ~256-bit.", "post_quantum_status" => 3, "example" => ["scenario" => "Russian high-security archive", "input" => ["archive" => "Защищенный государственный архив"], "output" => ["hash" => "c0c8c5d3e7f1a5b9c3d7e1f5a9b3c7d1e5f9a3b7c1d5e9f3a7b1c5d9e3f7a1b5c9d3e7f1a5b9c3d7e1f5a9b3c7d1e5f9a3b7c1d5e9f3"]], "flow" => ["gost 512-bit cipher", "64 rounds", "512-bit digest"], "related" => ["streebog256"]],
    ],
    "new" => [
        ["algo" => 100, "uuid" => "935246", "name" => "poseidon", "type" => "hash", "status" => "new", "title" => "Poseidon", "description_md" => "Poseidon is a cryptographic hash designed for zero-knowledge proofs and blockchain applications by StarkWare. Optimized for arithmetic circuits (efficient in zk-proofs). Uses S-boxes over prime fields. Produces variable output. Excellent for post-quantum zero-knowledge systems. Good cryptanalysis for ZK use. No practical attacks. Grover reduces security by sqrt. Used in Ethereum layer-2 (StarkNet) and zk-SNARK systems. Emerging standard for ZK-friendly hashing. Critical for post-quantum ZK protocols.", "mental_model" => "Arithmetic circuit hash for zero-knowledge.", "purpose" => ["zk-proof hash", "blockchain"], "good_for" => ["zero-knowledge proofs", "starknet", "layer-2"], "avoid_for" => ["general hashing"], "pros" => ["zk-friendly", "post-quantum prep", "arithmetic efficient"], "cons" => ["specialized", "zk-only"], "difficulty" => 3, "security" => 4, "quantum_impact" => "Grover reduces security by sqrt.", "post_quantum_status" => 4, "example" => ["scenario" => "ZK proof hash", "input" => ["statement" => "0xa1b2c3d4e5f6a7b8", "witness" => "0xf1a2b3c4d5e6f7a8"], "output" => ["poseidon_hash" => "0x123456789abcdef0123456789abcdef0123456789abcdef0123456789abcdef0"]], "flow" => ["arithmetic circuit", "sbox over prime", "variable output"], "related" => ["mimc", "rescue"]],
        ["algo" => 101, "uuid" => "521c86", "name" => "pedersen-hash", "type" => "hash", "status" => "new", "title" => "Pedersen Hash", "description_md" => "Pedersen Hash is an elliptic curve-based hash (not cryptographic hash) used in ZK systems. Based on discrete logarithm problem. Produces points on elliptic curve. Used in privacy systems (Zcash) and ZK circuits. Not a traditional hash; outputs group element. Security from DLP hardness. Grover reduces security by sqrt. Post-quantum it's broken (DLP broken by Shor). Used when ZK systems require group operations. Important for understanding ZK-friendly alternatives to traditional hashing. Avoid for post-quantum systems.", "mental_model" => "Elliptic curve based privacy hash.", "purpose" => ["zk hash", "privacy"], "good_for" => ["zcash", "privacy systems", "zk circuits"], "avoid_for" => ["post-quantum systems"], "pros" => ["privacy friendly", "zk efficient", "group based"], "cons" => ["post-quantum broken", "not traditional hash"], "difficulty" => 3, "security" => 3, "quantum_impact" => "Shor attack breaks DLP.", "post_quantum_status" => 1, "example" => ["scenario" => "Zcash note commitment", "input" => ["base_point" => "G", "scalar" => "0x3f4a1b2c"], "output" => ["curve_point" => "0x04a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6e7f8a9"]], "flow" => ["scalar mult on curve", "sum group elements", "point output"], "related" => ["poseidon", "mimc"]],
        ["algo" => 102, "uuid" => "f86023", "name" => "mimc", "type" => "hash", "status" => "new", "title" => "MiMC", "description_md" => "MiMC (Minimal Multiplicative Complexity) is a hash and cipher design optimized for zero-knowledge proof systems. Uses minimal multiplications over a prime field, making it extremely efficient inside arithmetic circuits used by zk-SNARKs and STARKs. MiMC-p/q variant supports both permutation and sponge hashing modes. It is purpose-built for systems like Ethereum smart contracts that require on-chain proof verification. No practical attacks on well-parameterized MiMC. Security depends on correct round constant and field choice. Grover reduces security by sqrt. Not suitable for general-purpose hashing outside ZK context. Use Poseidon or BLAKE2 outside ZK.", "mental_model" => "Minimal-multiply hash for ZK circuits.", "purpose" => ["zk hash", "arithmetic circuit"], "good_for" => ["zk-snarks", "ethereum smart contracts", "starknet"], "avoid_for" => ["general hashing", "non-zk applications"], "pros" => ["minimal multiplications", "zk efficient", "sponge mode"], "cons" => ["zk-only", "less analyzed than sha3"], "difficulty" => 3, "security" => 4, "quantum_impact" => "Grover reduces security by sqrt.", "post_quantum_status" => 3, "example" => ["scenario" => "Ethereum ZK rollup leaf hash", "input" => ["field_elem_a" => "0x1a2b3c4d5e6f7a8b9c0d1e2f3a4b5c6d", "field_elem_b" => "0x7e8f9a0b1c2d3e4f5a6b7c8d9e0f1a2b"], "output" => ["mimc_hash" => "0x3c4d5e6f7a8b9c0d1e2f3a4b5c6d7e8f9a0b1c2d3e4f5a6b7c8d9e0f1a2b3c"]], "flow" => ["field elem input", "cube rounds", "add round constant", "sponge output"], "related" => ["poseidon", "rescue"]],
        ["algo" => 103, "uuid" => "9fb2b3", "name" => "rescue", "type" => "hash", "status" => "new", "title" => "Rescue", "description_md" => "Rescue is an algebraic hash function designed for ZK-proof systems by Aly, Ashur, Ben-Sasson, Dhooghe, and Szepieniec. Uses both x^alpha and x^(1/alpha) S-boxes over prime fields for provable security in algebraic settings. Designed to resist Groebner basis and interpolation attacks that threaten simpler ZK hashes. Strong security arguments in the arithmetic circuit model. Being analyzed as a candidate for ZK-friendly hashing. No practical attacks found. Grover reduces security by sqrt. Harder to implement than MiMC but stronger security guarantees. Use Poseidon for simpler ZK hashing or Rescue where formal security proof matters.", "mental_model" => "Formally proven ZK hash with dual S-boxes.", "purpose" => ["zk hash", "provable security"], "good_for" => ["zk-snarks", "formal verification", "starks"], "avoid_for" => ["general hashing"], "pros" => ["provable security", "algebraic resistance", "dual sbox"], "cons" => ["complex", "zk-only", "less deployed"], "difficulty" => 4, "security" => 4, "quantum_impact" => "Grover reduces security by sqrt.", "post_quantum_status" => 4, "example" => ["scenario" => "STARK proof leaf commitment", "input" => ["field_a" => "0x2b3c4d5e6f7a8b9c0d1e2f3a4b5c6d7e", "field_b" => "0x8f9a0b1c2d3e4f5a6b7c8d9e0f1a2b3c"], "output" => ["rescue_hash" => "0x5e6f7a8b9c0d1e2f3a4b5c6d7e8f9a0b1c2d3e4f5a6b7c8d9e0f1a2b3c4d5e"]], "flow" => ["prime field input", "x^alpha sbox", "x^(1/alpha) sbox", "MDS mix", "sponge output"], "related" => ["poseidon", "mimc"]],
        ["algo" => 104, "uuid" => "308d8a", "name" => "griffin", "type" => "hash", "status" => "new", "title" => "Griffin", "description_md" => "Griffin is a ZK-friendly hash function designed by Grassi, Khovratovich, Lucks, and Schofnegger (2022). Combines non-linear power maps with linear layers for efficient proof generation. Griffin targets both zk-SNARK and zk-STARK backends. Uses a hybrid design: Feistel-like network over prime fields. Fewer constraints than Poseidon for equivalent security in some circuit backends. Active area of research; being evaluated for deployment in ZK infrastructure. No practical attacks found. Grover reduces security by sqrt. Strong candidate for next-generation ZK hashing. Implementation complexity is higher than Poseidon.", "mental_model" => "Next-gen Feistel ZK hash.", "purpose" => ["zk hash", "circuit optimization"], "good_for" => ["zk-snarks", "zk-starks", "next-gen zk infra"], "avoid_for" => ["general hashing", "legacy systems"], "pros" => ["fewer constraints", "snark+stark compatible", "hybrid design"], "cons" => ["experimental", "complex", "less analyzed than poseidon"], "difficulty" => 4, "security" => 4, "quantum_impact" => "Grover reduces security by sqrt.", "post_quantum_status" => 4, "example" => ["scenario" => "ZK-STARK proof hash", "input" => ["field_x" => "0x4c5d6e7f8a9b0c1d2e3f4a5b6c7d8e9f", "field_y" => "0x0a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d"], "output" => ["griffin_hash" => "0x7f8a9b0c1d2e3f4a5b6c7d8e9f0a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6e7f"]], "flow" => ["prime field input", "non-linear power map", "feistel rounds", "linear mix", "output"], "related" => ["poseidon", "rescue"]],
        ["algo" => 105, "uuid" => "08650e", "name" => "reinforced-concrete", "type" => "hash", "status" => "new", "title" => "Reinforced Concrete", "description_md" => "Reinforced Concrete is a ZK-friendly hash by Grassi, Khovratovich, Rechberger, Roy, and Schofnegger (2021). Designed to be efficiently verifiable inside arithmetic circuits while also being fast in software. Combines concrete (non-ZK) hash ideas with algebraic S-boxes to balance native speed and circuit efficiency. Uses decomposition into small chunks with lookup-table-friendly structure. Targets both Plonk and Groth16 proving systems. No practical attacks known. Strong security arguments. Grover reduces security by sqrt. More complex than MiMC; suited for systems that need fast native execution alongside circuit proving.", "mental_model" => "Hybrid native+circuit hash for ZK.", "purpose" => ["zk hash", "native speed"], "good_for" => ["plonk circuits", "groth16", "fast native ZK"], "avoid_for" => ["general hashing"], "pros" => ["native speed", "circuit efficient", "lookup friendly"], "cons" => ["complex", "experimental", "zk specific"], "difficulty" => 4, "security" => 4, "quantum_impact" => "Grover reduces security by sqrt.", "post_quantum_status" => 4, "example" => ["scenario" => "Plonk circuit leaf hash", "input" => ["chunk_a" => "0x1c2d3e4f5a6b7c8d", "chunk_b" => "0x9e0f1a2b3c4d5e6f"], "output" => ["rc_hash" => "0xa3b4c5d6e7f8a9b0c1d2e3f4a5b6c7d8e9f0a1b2c3d4e5f6a7b8c9d0e1f2a3"]], "flow" => ["chunk decompose", "algebraic sbox", "lookup layer", "MDS mix", "output"], "related" => ["poseidon", "griffin"]],
        ["algo" => 106, "uuid" => "b1662f", "name" => "haraka", "type" => "hash", "status" => "new", "title" => "Haraka", "description_md" => "Haraka is a short-input hash function designed by Khovratovich, Rechberger, and Savelieva (2016) for high speed on AES-NI hardware. Targets 256-bit and 512-bit inputs producing 256-bit output. Uses AES round functions natively, making it extremely fast on modern x86 CPUs with AES-NI. Designed for use in hash-based signature schemes (SPHINCS+) and Merkle tree computation where many short hashes are needed. Not suitable for arbitrary-length hashing; restricted to fixed-size inputs. No practical attacks. Grover reduces to 128-bit security. Use when hashing many small fixed-size values on AES-NI hardware.", "mental_model" => "AES-NI turbo hash for fixed-size inputs.", "purpose" => ["short-input hash", "aes-ni fast"], "good_for" => ["sphincs+", "merkle trees", "aes-ni systems"], "avoid_for" => ["variable-length data", "non-aes hardware"], "pros" => ["extremely fast on aes-ni", "256-bit output", "sphincs compatible"], "cons" => ["fixed input size only", "hardware dependent"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Grover reduces 256-bit to ~128-bit.", "post_quantum_status" => 3, "example" => ["scenario" => "SPHINCS+ Merkle tree node hash", "input" => ["left_node" => "a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5d6", "right_node" => "e7f8a9b0c1d2e3f4a5b6c7d8e9f0a1b2"], "output" => ["node_hash" => "3c4d5e6f7a8b9c0d1e2f3a4b5c6d7e8f9a0b1c2d3e4f5a6b7c8d9e0f1a2b3c"]], "flow" => ["fixed input", "aes rounds", "linear mix", "256-bit digest"], "related" => ["sha256", "blake2s"]],
        ["algo" => 107, "uuid" => "2eb8e7", "name" => "lsh", "type" => "hash", "status" => "new", "title" => "LSH", "description_md" => "LSH (Learned Similarity Hash / Korean Standard Hash) is the Korean cryptographic hash standard designed by NSRI (National Security Research Institute). Produces 224, 256, 384, or 512-bit output. Designed for high performance on 32 and 64-bit platforms without SIMD. Based on wide-pipe Merkle-Damgard structure with custom word operations. Adopted as Korean standard (KS X 3262). Good cryptanalysis. No practical attacks. Performance comparable to SHA-256. Grover reduces security by half output bits. Required for Korean government systems. For international use, SHA-2 or SHA-3 is preferred.", "mental_model" => "Korean government standard hash.", "purpose" => ["compute hash", "korean compatibility"], "good_for" => ["korean government systems", "korean banking"], "avoid_for" => ["unless required by korean standard"], "pros" => ["256/512-bit output", "korean standard", "good performance"], "cons" => ["limited international adoption", "niche"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Grover reduces security by sqrt.", "post_quantum_status" => 3, "example" => ["scenario" => "Korean government document hash", "input" => ["document_id" => "KR-GOV-2024-00831", "content_hash_seed" => "ab12cd34ef56"], "output" => ["lsh256" => "b4c5d6e7f8a9b0c1d2e3f4a5b6c7d8e9f0a1b2c3d4e5f6a7b8c9d0e1f2a3b4"]], "flow" => ["wide-pipe merkle-damgard", "word operations", "compression", "digest"], "related" => ["sha256", "sm3", "streebog256"]],
        ["algo" => 108, "uuid" => "6efd19", "name" => "highwayhash", "type" => "hash", "status" => "new", "title" => "HighwayHash", "description_md" => "HighwayHash is a fast non-cryptographic hash by Google (Alakuijala and Luo, 2016). Designed for high throughput on modern 64-bit CPUs using SIMD (AVX2, SSE4.1, NEON). Produces 64, 128, or 256-bit output. Not intended for cryptographic security; optimized for speed in hash tables, checksums, and fingerprinting. Very fast: several GB/s throughput. Used in Google infrastructure for data deduplication and integrity. No collision resistance guarantees for adversarial inputs. Do not use for security-critical applications. SipHash or BLAKE3 are better choices when security matters.", "mental_model" => "Google SIMD turbo hash for fingerprinting.", "purpose" => ["fingerprint", "checksum", "hash table"], "good_for" => ["data deduplication", "checksums", "hash tables", "google infra"], "avoid_for" => ["security applications", "adversarial inputs"], "pros" => ["extremely fast", "simd optimized", "64/128/256-bit output"], "cons" => ["not cryptographic", "no collision guarantee vs adversary"], "difficulty" => 1, "security" => 2, "quantum_impact" => "Not cryptographic; quantum irrelevant.", "post_quantum_status" => 1, "example" => ["scenario" => "Large file deduplication fingerprint", "input" => ["file" => "backup_2024_full.tar.gz", "seed" => "0xdeadbeefcafe1234"], "output" => ["hash64" => "0xa3f1c2e4b5d6a7f8", "hash128" => "0xa3f1c2e4b5d6a7f8b9c0d1e2f3a4b5c6"]], "flow" => ["simd lanes", "mix rounds", "finalize", "64/128/256 output"], "related" => ["siphash", "xxhash", "farmhash"]],
        ["algo" => 109, "uuid" => "4659e9", "name" => "mgf1", "type" => "hash", "status" => "new", "title" => "MGF1", "description_md" => "MGF1 (Mask Generation Function 1) is a mask generation function defined in PKCS#1 and RFC 8017. It is not a standalone hash; it is a variable-length output function built on top of a hash (usually SHA-256 or SHA-1). MGF1 is a core component of OAEP (RSA encryption padding) and PSS (RSA signature padding). It expands a seed into an arbitrary-length pseudorandom byte stream. Security depends entirely on the underlying hash. With SHA-256, output is computationally indistinguishable from random for adversaries without the seed. Grover reduces security by sqrt. Required for RSA-OAEP/PSS compliance. Do not use directly; use OAEP or PSS that internally calls MGF1.", "mental_model" => "PKCS1 mask generator built on a hash.", "purpose" => ["mask generation", "rsa padding"], "good_for" => ["rsa-oaep", "rsa-pss", "pkcs1 compliance"], "avoid_for" => ["direct use", "general hashing"], "pros" => ["standard", "variable output", "rsa compat"], "cons" => ["not standalone", "depends on underlying hash", "rsa specific"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Grover reduces underlying hash security by sqrt.", "post_quantum_status" => 2, "example" => ["scenario" => "RSA-OAEP encryption padding", "input" => ["seed" => "f4a1b2c3d4e5f6a7b8c9d0e1f2a3b4c5", "length" => 32, "hash" => "sha256"], "output" => ["mask" => "7c8d9e0f1a2b3c4d5e6f7a8b9c0d1e2f3a4b5c6d7e8f9a0b1c2d3e4f5a6b7c8"]], "flow" => ["seed + counter", "hash(seed || counter)", "concat blocks", "truncate to length"], "related" => ["rsa-oaep", "rsa-pss", "sha256"]],
    ]
];
?>